// MAIN PAGE
// ══════════════════════════════════════════════════════════════════════════════
export default function SettingPage() {
  const params = useParams();
  const restaurantId = params?.restaurantId;
  const [activeTab, setActiveTab] = useState("profile");
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [settings, setSettings] = useState({
    profile: {
      name: "",
      email: "",
      phone: "",
      description: "",
      category: "",
    },
    restaurant: {
      address: "",
      city: "",
      country: "",
      zipCode: "",
      mallName: "",
      hours: "",
      website: "",
      phone: "",
      email: "",
      name: "",
      description: "",
    },
    notifications: {
      orderAlerts: true,
      tableAlerts: true,
      lowStockAlerts: false,
      emailNotifications: false,
    },
    orders: {
      minOrderValue: 0,
      deliveryFee: 0,
      taxRate: 10,
      acceptingOrders: true,
    },
    media: {
      logo: null,
      heroImage: null,
    },
  });

  // Load settings on mount
  useEffect(() => {
    if (!restaurantId) return;
    const loadSettings = async () => {
      try {
        setLoading(true);
        const res = await fetch(`/api/restaurants/${restaurantId}/settings`);
        if (!res.ok) throw new Error("Failed to load settings");
        const data = await res.json();
        setSettings(data);
        setError("");
      } catch (err) {
        console.error("Error loading settings:", err);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    loadSettings();
  }, [restaurantId]);

  async function handleSave() {
    if (!restaurantId) return;
    setSaving(true);
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/settings`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(settings),
      });
      if (!res.ok) throw new Error("Failed to save settings");
      setSaved(true);
      setError("");
      setTimeout(() => setSaved(false), 2500);
    } catch (err) {
      console.error("Error saving settings:", err);
      setError(err.message);
    } finally {
      setSaving(false);
    }
  }

  const tabContent = {
    profile: (
      <ProfileTab
        settings={settings}
        onSettingsChange={setSettings}
        restaurantId={restaurantId}
      />
    ),
    restaurant: (
      <RestaurantTab
        settings={settings}
        onSettingsChange={setSettings}
        restaurantId={restaurantId}
      />
    ),
    notifications: (
      <NotificationsTab settings={settings} onSettingsChange={setSettings} />
    ),
    orders: (
      <OrderSettingsTab settings={settings} onSettingsChange={setSettings} />
    ),
    developer: <DeveloperTab restaurantId={restaurantId} />,
    billing: <BillingTab />,
  };

  if (!restaurantId) {
    return (
      <div className="flex items-center justify-center p-8 text-gray-400">
        Loading...
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <Loader2 className="animate-spin mx-auto mb-3 text-emerald-500" />
          <p className="text-gray-600 dark:text-gray-400">
            Loading settings...
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-[#080f1e]">
      {/* ── Sticky tab bar ── */}
      <div className="sticky top-0 z-20 bg-white dark:bg-[#0a1020] border-b border-gray-200 dark:border-white/10 shadow-sm">
        <div className="max-w-5xl mx-auto px-4">
          <div className="flex items-center gap-1 overflow-x-auto scrollbar-hide">
            {TABS.map(({ id, label, icon: Icon }) => (
              <button
                key={id}
                onClick={() => setActiveTab(id)}
                className={`flex items-center gap-2 px-4 py-4 whitespace-nowrap text-sm font-medium border-b-2 transition-colors
                  ${
                    activeTab === id
                      ? "border-emerald-500 text-emerald-600 dark:text-emerald-400"
                      : "border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
                  }`}
              >
                <Icon size={16} />
                {label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* ── Page header ── */}
      <div className="max-w-5xl mx-auto px-4 py-6">
        {error && (
          <div className="mb-4 flex items-center gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg text-sm">
            <AlertCircle size={16} />
            {error}
          </div>
        )}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-gray-100 dark:bg-white/10 rounded-xl flex items-center justify-center">
              {(() => {
                const T = TABS.find((t) => t.id === activeTab);
                return T ? (
                  <T.icon
                    size={18}
                    className="text-gray-600 dark:text-gray-300"
                  />
                ) : null;
              })()}
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 dark:text-white">
                {TABS.find((t) => t.id === activeTab)?.label} Settings
              </h1>
              <p className="text-xs text-gray-400">
                Manage your{" "}
                {TABS.find((t) => t.id === activeTab)?.label.toLowerCase()}{" "}
                preferences
              </p>
            </div>
          </div>

          {/* Save button — hidden on billing & developer (read-only) */}
          {activeTab !== "billing" && activeTab !== "developer" && (
            <button
              onClick={handleSave}
              disabled={saving}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-semibold text-sm transition
                ${
                  saved
                    ? "bg-emerald-100 text-emerald-700 dark:bg-emerald-950/40 dark:text-emerald-400"
                    : "bg-emerald-500 hover:bg-emerald-600 text-white shadow-sm"
                } disabled:opacity-60`}
            >
              {saving ? (
                <Loader2 size={15} className="animate-spin" />
              ) : saved ? (
                <>
                  <Check size={15} /> Saved!
                </>
              ) : (
                <>
                  <Save size={15} /> Save Changes
                </>
              )}
            </button>
          )}
        </div>

        {/* ── Tab content ── */}
        <div className="bg-white dark:bg-[#0a1020] rounded-2xl border border-gray-200 dark:border-white/10 p-6 shadow-sm">
          {tabContent[activeTab]}
        </div>
      </div>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
}

// app/(dashboard)/dashboard/[restaurantId]/settings/page.jsx
"use client";

import { useParams } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import {
  ImagePlus,
  Trash2,
  Loader2,
  CheckCircle,
  AlertCircle,
  UploadCloud,
  User,
  UtensilsCrossed,
  Bell,
  ShoppingCart,
  Wifi,
  CreditCard,
  Save,
  Camera,
  Plus,
  Copy,
  Eye,
  EyeOff,
  Trash,
  Check,
  X,
} from "lucide-react";
import { toast } from "sonner";

const TABS = [
  { id: "profile", label: "Profile", icon: User },
  { id: "restaurant", label: "Restaurant", icon: UtensilsCrossed },
  { id: "notifications", label: "Notifications", icon: Bell },
  { id: "orders", label: "Order Settings", icon: ShoppingCart },
  { id: "developer", label: "Developer", icon: Wifi },
  { id: "billing", label: "Billing", icon: CreditCard },
];

// ── Input components ──────────────────────────────────────────────────────────
function Input({ ...props }) {
  return (
    <input
      {...props}
      className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-white/10
                 bg-white dark:bg-white/5 text-gray-900 dark:text-white
                 placeholder:text-gray-400 dark:placeholder:text-gray-500
                 focus:outline-none focus:ring-2 focus:ring-emerald-500
                 transition text-sm"
    />
  );
}

function Textarea({ ...props }) {
  return (
    <textarea
      {...props}
      className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-white/10
                 bg-white dark:bg-white/5 text-gray-900 dark:text-white
                 placeholder:text-gray-400 dark:placeholder:text-gray-500
                 focus:outline-none focus:ring-2 focus:ring-emerald-500
                 transition text-sm resize-none min-h-[100px]"
    />
  );
}

function Toggle({ checked, onChange }) {
  return (
    <button
      onClick={() => onChange(!checked)}
      className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
        checked ? "bg-emerald-500" : "bg-gray-300 dark:bg-gray-600"
      }`}
    >
      <span
        className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
          checked ? "translate-x-6" : "translate-x-1"
        }`}
      />
    </button>
  );
}

// ── Logo Uploader ─────────────────────────────────────────────────────────────
function LogoUploader({ restaurantId, currentLogo }) {
  const inputRef = useRef(null);
  const [preview, setPreview] = useState(currentLogo || null);
  const [uploading, setUploading] = useState(false);

  async function handleFile(f) {
    if (!f?.type.startsWith("image/")) {
      toast.error("Please select an image file");
      return;
    }
    setPreview(URL.createObjectURL(f));
    setUploading(true);
    try {
      const form = new FormData();
      form.append("file", f);
      const res = await fetch(`/api/restaurants/${restaurantId}/logo`, {
        method: "POST",
        body: form,
      });
      if (res.ok) {
        toast.success("Logo updated");
      } else {
        toast.error("Failed to upload logo");
      }
    } catch (err) {
      toast.error("Upload error: " + err.message);
    } finally {
      setUploading(false);
    }
  }

  async function handleDelete() {
    if (!confirm("Delete logo?")) return;
    setUploading(true);
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/logo`, {
        method: "DELETE",
      });
      if (res.ok) {
        setPreview(null);
        toast.success("Logo removed");
      }
    } catch (err) {
      toast.error("Delete error");
    } finally {
      setUploading(false);
    }
  }

  return (
    <div className="space-y-3">
      <p className="text-sm font-medium">Logo</p>
      <div
        className="relative w-32 h-32 rounded-xl overflow-hidden border-2 border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-white/5 group cursor-pointer"
        onClick={() => inputRef.current?.click()}
      >
        {preview ? (
          <img
            src={preview}
            alt="Logo"
            className="w-full h-full object-cover"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center gap-1">
            <Camera size={22} className="text-gray-400" />
            <span className="text-xs text-gray-400">Upload</span>
          </div>
        )}
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
          {uploading ? (
            <Loader2 size={18} className="text-white animate-spin" />
          ) : (
            <Camera size={18} className="text-white" />
          )}
        </div>
        {preview && (
          <button
            onClick={(e) => {
              e.stopPropagation();
              handleDelete();
            }}
            className="absolute top-2 right-2 w-6 h-6 bg-red-500 text-white rounded flex items-center justify-center"
          >
            <X size={12} />
          </button>
        )}
      </div>
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={(e) => handleFile(e.target.files?.[0])}
      />
    </div>
  );
}

// ── Hero Uploader ─────────────────────────────────────────────────────────────
function HeroUploader({ restaurantId, currentHero }) {
  const inputRef = useRef(null);
  const [preview, setPreview] = useState(currentHero || null);
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);

  async function handleUpload() {
    if (!file) return;
    setUploading(true);
    try {
      const form = new FormData();
      form.append("file", file);
      const res = await fetch(`/api/restaurants/${restaurantId}/hero-image`, {
        method: "POST",
        body: form,
      });
      if (res.ok) {
        setFile(null);
        toast.success("Hero image updated");
      } else {
        toast.error("Upload failed");
      }
    } catch (err) {
      toast.error("Upload error");
    } finally {
      setUploading(false);
    }
  }

  async function handleDelete() {
    if (!confirm("Remove hero image?")) return;
    setUploading(true);
    try {
      await fetch(`/api/restaurants/${restaurantId}/hero-image`, {
        method: "DELETE",
      });
      setPreview(null);
      setFile(null);
      toast.success("Hero image removed");
    } catch (err) {
      toast.error("Delete error");
    } finally {
      setUploading(false);
    }
  }

  return (
    <div className="space-y-3">
      <p className="text-sm font-medium">Hero Image (1920x600px)</p>
      <div
        onDragOver={(e) => e.preventDefault()}
        onDrop={(e) => {
          e.preventDefault();
          const f = e.dataTransfer.files?.[0];
          if (f?.type.startsWith("image/")) {
            setFile(f);
            setPreview(URL.createObjectURL(f));
          }
        }}
        onClick={() => inputRef.current?.click()}
        className="relative w-full h-40 rounded-lg border-2 border-dashed border-gray-300 dark:border-white/10 bg-gray-50 dark:bg-white/5 cursor-pointer flex items-center justify-center hover:border-orange-500 transition"
      >
        {preview ? (
          <img
            src={preview}
            alt="Hero"
            className="w-full h-full object-cover"
          />
        ) : (
          <div className="text-center">
            <UploadCloud className="mx-auto mb-2 text-gray-400" size={24} />
            <p className="text-sm text-gray-500">Drag or click to upload</p>
          </div>
        )}
      </div>
      <div className="flex gap-2">
        {file && (
          <button
            onClick={handleUpload}
            disabled={uploading}
            className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 disabled:opacity-50"
          >
            {uploading ? (
              <>
                <Loader2 size={16} className="animate-spin" /> Uploading
              </>
            ) : (
              <>
                <CheckCircle size={16} /> Upload
              </>
            )}
          </button>
        )}
        {preview && !file && (
          <button
            onClick={handleDelete}
            className="px-4 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50"
          >
            <Trash size={16} />
          </button>
        )}
      </div>
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={(e) => {
          const f = e.target.files?.[0];
          if (f) {
            setFile(f);
            setPreview(URL.createObjectURL(f));
          }
        }}
      />
    </div>
  );
}

// ── API Keys Section ──────────────────────────────────────────────────────────
function APIKeysSection({ restaurantId }) {
  const [apiKeys, setApiKeys] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newKeyName, setNewKeyName] = useState("");
  const [createdKey, setCreatedKey] = useState(null);
  const [showKey, setShowKey] = useState(false);

  useEffect(() => {
    loadApiKeys();
  }, [restaurantId]);

  async function loadApiKeys() {
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/api-keys`);
      const data = await res.json();
      setApiKeys(data.apiKeys || []);
    } catch (err) {
      console.error("Failed to load API keys:", err);
    } finally {
      setLoading(false);
    }
  }

  async function createApiKey() {
    if (!newKeyName) {
      toast.error("Enter a key name");
      return;
    }
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/api-keys`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newKeyName }),
      });
      const data = await res.json();
      setCreatedKey(data);
      setNewKeyName("");
      loadApiKeys();
      toast.success("API key created");
    } catch (err) {
      toast.error("Failed to create key");
    }
  }

  async function deleteApiKey(id) {
    if (!confirm("Delete this key?")) return;
    try {
      await fetch(`/api/restaurants/${restaurantId}/api-keys`, {
        method: "DELETE",
      });
      loadApiKeys();
      toast.success("Key deleted");
    } catch (err) {
      toast.error("Failed to delete key");
    }
  }

  return (
    <div className="space-y-6">
      {createdKey && (
        <div className="p-4 bg-emerald-50 dark:bg-emerald-950/20 border border-emerald-200 dark:border-emerald-800 rounded-lg">
          <p className="text-sm font-medium text-emerald-900 dark:text-emerald-300 mb-2">
            Save your API key (shown only once):
          </p>
          <div className="flex items-center gap-2">
            <input
              type={showKey ? "text" : "password"}
              value={createdKey.key}
              readOnly
              className="flex-1 px-3 py-2 bg-white dark:bg-white/10 border rounded text-sm"
            />
            <button
              onClick={() => setShowKey(!showKey)}
              className="p-2 hover:bg-emerald-100 dark:hover:bg-emerald-900/30 rounded"
            >
              {showKey ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
            <button
              onClick={() => {
                navigator.clipboard.writeText(createdKey.key);
                toast.success("Copied!");
              }}
              className="p-2 hover:bg-emerald-100 dark:hover:bg-emerald-900/30 rounded"
            >
              <Copy size={16} />
            </button>
          </div>
          <button
            onClick={() => setCreatedKey(null)}
            className="mt-2 text-sm text-emerald-600 dark:text-emerald-400 hover:underline"
          >
            Dismiss
          </button>
        </div>
      )}

      <div className="space-y-2">
        <label className="text-sm font-medium">Create new API key</label>
        <div className="flex gap-2">
          <Input
            placeholder="Key name (e.g., Production, Testing)"
            value={newKeyName}
            onChange={(e) => setNewKeyName(e.target.value)}
          />
          <button
            onClick={createApiKey}
            className="px-4 py-2 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 whitespace-nowrap flex items-center gap-2"
          >
            <Plus size={16} /> Create
          </button>
        </div>
      </div>

      <div className="space-y-2">
        <h3 className="text-sm font-medium">Active keys</h3>
        {loading ? (
          <p className="text-sm text-gray-500">Loading...</p>
        ) : apiKeys.length === 0 ? (
          <p className="text-sm text-gray-500">No API keys created</p>
        ) : (
          <div className="space-y-2">
            {apiKeys.map((key) => (
              <div
                key={key.id}
                className="flex items-center justify-between p-3 bg-gray-50 dark:bg-white/5 rounded-lg border border-gray-200 dark:border-white/10"
              >
                <div>
                  <p className="text-sm font-medium">{key.name}</p>
                  <p className="text-xs text-gray-500">
                    **{key.lastChars} • Created{" "}
                    {new Date(key.createdAt).toLocaleDateString()}
                  </p>
                </div>
                <button
                  onClick={() => deleteApiKey(key.id)}
                  className="p-2 text-red-600 hover:bg-red-50 dark:hover:bg-red-950/30 rounded"
                >
                  <Trash size={16} />
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── Main Settings Component ───────────────────────────────────────────────────
export default function SettingsPage() {
  const params = useParams();
  const restaurantId = params?.restaurantId;

  const [activeTab, setActiveTab] = useState("profile");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [settings, setSettings] = useState({
    profile: {
      name: "",
      email: "",
      phone: "",
      description: "",
      category: "",
    },
    restaurant: {
      address: "",
      city: "",
      country: "",
      zipCode: "",
      mallName: "",
      hours: "",
    },
    notifications: {
      orderAlerts: true,
      tableAlerts: true,
      lowStockAlerts: true,
      emailNotifications: true,
    },
    orders: {
      minOrderValue: 0,
      deliveryFee: 0,
      taxRate: 10,
      acceptingOrders: true,
    },
    media: {
      logo: null,
      heroImage: null,
    },
  });

  // Load settings on mount
  useEffect(() => {
    if (!restaurantId) return;
    loadSettings();
  }, [restaurantId]);

  async function loadSettings() {
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/settings`);
      const data = await res.json();
      setSettings(data);
    } catch (err) {
      toast.error("Failed to load settings");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  async function saveSettings() {
    setSaving(true);
    try {
      const res = await fetch(`/api/restaurants/${restaurantId}/settings`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(settings),
      });
      if (res.ok) {
        toast.success("Settings saved");
      } else {
        toast.error("Failed to save settings");
      }
    } catch (err) {
      toast.error("Error saving settings");
    } finally {
      setSaving(false);
    }
  }

  if (!restaurantId || loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <Loader2 className="animate-spin" size={32} />
      </div>
    );
  }

  return (
    <div className="space-y-6 pb-20">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold">Settings</h1>
        <button
          onClick={saveSettings}
          disabled={saving}
          className="flex items-center gap-2 px-6 py-2.5 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 disabled:opacity-50"
        >
          {saving ? (
            <>
              <Loader2 size={16} className="animate-spin" /> Saving
            </>
          ) : (
            <>
              <Save size={16} /> Save Changes
            </>
          )}
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 border-b border-gray-200 dark:border-white/10 overflow-x-auto">
        {TABS.map((tab) => {
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-4 py-3 border-b-2 transition whitespace-nowrap ${
                activeTab === tab.id
                  ? "border-emerald-500 text-emerald-600 dark:text-emerald-400"
                  : "border-transparent text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-300"
              }`}
            >
              <Icon size={18} />
              <span className="text-sm font-medium">{tab.label}</span>
            </button>
          );
        })}
      </div>

      {/* Content */}
      <div className="bg-white dark:bg-white/5 rounded-xl border border-gray-200 dark:border-white/10 p-6">
        {/* Profile Tab */}
        {activeTab === "profile" && (
          <div className="space-y-6">
            <div className="flex gap-6">
              <LogoUploader
                restaurantId={restaurantId}
                currentLogo={settings.media?.logo}
              />
              <div className="flex-1 space-y-4">
                <div>
                  <label className="text-sm font-medium">Restaurant Name</label>
                  <Input
                    value={settings.profile.name}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        profile: { ...settings.profile, name: e.target.value },
                      })
                    }
                  />
                </div>
                <div>
                  <label className="text-sm font-medium">Email</label>
                  <Input
                    type="email"
                    value={settings.profile.email}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        profile: { ...settings.profile, email: e.target.value },
                      })
                    }
                  />
                </div>
                <div>
                  <label className="text-sm font-medium">Phone</label>
                  <Input
                    value={settings.profile.phone}
                    onChange={(e) =>
                      setSettings({
                        ...settings,
                        profile: { ...settings.profile, phone: e.target.value },
                      })
                    }
                  />
                </div>
              </div>
            </div>
            <div>
              <label className="text-sm font-medium">Description</label>
              <Textarea
                value={settings.profile.description}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    profile: {
                      ...settings.profile,
                      description: e.target.value,
                    },
                  })
                }
              />
            </div>
            <div>
              <label className="text-sm font-medium">Category</label>
              <select
                value={settings.profile.category}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    profile: { ...settings.profile, category: e.target.value },
                  })
                }
                className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-white/10 bg-white dark:bg-white/5"
              >
                <option value="">Select category</option>
                <option value="italian">Italian</option>
                <option value="chinese">Chinese</option>
                <option value="indian">Indian</option>
                <option value="fast-food">Fast Food</option>
                <option value="desserts">Desserts</option>
                <option value="beverages">Beverages</option>
              </select>
            </div>
          </div>
        )}

        {/* Restaurant Tab */}
        {activeTab === "restaurant" && (
          <div className="space-y-6">
            <HeroUploader
              restaurantId={restaurantId}
              currentHero={settings.media?.heroImage}
            />
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium">Address</label>
                <Input
                  value={settings.restaurant.address}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        address: e.target.value,
                      },
                    })
                  }
                />
              </div>
              <div>
                <label className="text-sm font-medium">City</label>
                <Input
                  value={settings.restaurant.city}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        city: e.target.value,
                      },
                    })
                  }
                />
              </div>
              <div>
                <label className="text-sm font-medium">Country</label>
                <Input
                  value={settings.restaurant.country}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        country: e.target.value,
                      },
                    })
                  }
                />
              </div>
              <div>
                <label className="text-sm font-medium">Zip Code</label>
                <Input
                  value={settings.restaurant.zipCode}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        zipCode: e.target.value,
                      },
                    })
                  }
                />
              </div>
              <div>
                <label className="text-sm font-medium">Mall Name</label>
                <Input
                  value={settings.restaurant.mallName}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        mallName: e.target.value,
                      },
                    })
                  }
                />
              </div>
              <div>
                <label className="text-sm font-medium">Operating Hours</label>
                <Input
                  placeholder="e.g., 9 AM - 11 PM"
                  value={settings.restaurant.hours}
                  onChange={(e) =>
                    setSettings({
                      ...settings,
                      restaurant: {
                        ...settings.restaurant,
                        hours: e.target.value,
                      },
                    })
                  }
                />
              </div>
            </div>
          </div>
        )}

        {/* Notifications Tab */}
        {activeTab === "notifications" && (
          <div className="space-y-4">
            {Object.entries(settings.notifications).map(([key, value]) => (
              <div
                key={key}
                className="flex items-center justify-between p-4 bg-gray-50 dark:bg-white/5 rounded-lg"
              >
                <div>
                  <p className="font-medium capitalize">
                    {key.replace(/([A-Z])/g, " $1")}
                  </p>
                </div>
                <Toggle
                  checked={value}
                  onChange={(checked) =>
                    setSettings({
                      ...settings,
                      notifications: {
                        ...settings.notifications,
                        [key]: checked,
                      },
                    })
                  }
                />
              </div>
            ))}
          </div>
        )}

        {/* Order Settings Tab */}
        {activeTab === "orders" && (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium">Minimum Order Value</label>
              <Input
                type="number"
                value={settings.orders.minOrderValue}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    orders: {
                      ...settings.orders,
                      minOrderValue: parseFloat(e.target.value),
                    },
                  })
                }
              />
            </div>
            <div>
              <label className="text-sm font-medium">Delivery Fee</label>
              <Input
                type="number"
                value={settings.orders.deliveryFee}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    orders: {
                      ...settings.orders,
                      deliveryFee: parseFloat(e.target.value),
                    },
                  })
                }
              />
            </div>
            <div>
              <label className="text-sm font-medium">Tax Rate (%)</label>
              <Input
                type="number"
                value={settings.orders.taxRate}
                onChange={(e) =>
                  setSettings({
                    ...settings,
                    orders: {
                      ...settings.orders,
                      taxRate: parseFloat(e.target.value),
                    },
                  })
                }
              />
            </div>
            <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-white/5 rounded-lg">
              <p className="font-medium">Accepting Orders</p>
              <Toggle
                checked={settings.orders.acceptingOrders}
                onChange={(checked) =>
                  setSettings({
                    ...settings,
                    orders: {
                      ...settings.orders,
                      acceptingOrders: checked,
                    },
                  })
                }
              />
            </div>
          </div>
        )}

        {/* Developer Tab */}
        {activeTab === "developer" && (
          <APIKeysSection restaurantId={restaurantId} />
        )}

        {/* Billing Tab */}
        {activeTab === "billing" && (
          <div className="text-center py-12">
            <CreditCard size={48} className="mx-auto text-gray-300 mb-4" />
            <p className="text-gray-600 dark:text-gray-400">
              Billing features coming soon
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  Plus,
  Settings,
  Users,
  MapPin,
  DollarSign,
  CheckCircle,
  XCircle,
  Clock,
  RefreshCw,
  Trash2,
  Edit2,
  Save,
} from "lucide-react";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";

export default function TableManagementPage() {
  const [restaurant, setRestaurant] = useState(null);
  const [tables, setTables] = useState([]);
  const [configs, setConfigs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("overview"); // 'overview', 'config', 'occupied'

  // Config form state
  const [showConfigForm, setShowConfigForm] = useState(false);
  const [editingConfig, setEditingConfig] = useState(null);
  const [configForm, setConfigForm] = useState({
    area: "dine-in",
    capacity: 2,
    totalTables: 10,
    pricePerTable: 30,
  });

  useEffect(() => {
    loadRestaurant();
  }, []);

  useEffect(() => {
    if (restaurant?._id) {
      loadData();
    }
  }, [restaurant]);

  // Auto-release tables after 45 minutes
  useEffect(() => {
    if (!restaurant?._id) return;

    const autoReleaseInterval = setInterval(async () => {
      try {
        const now = new Date();
        const FORTY_FIVE_MINUTES = 45 * 60 * 1000; // 45 minutes in milliseconds

        for (const table of tables) {
          if (table.isOccupied && table.occupiedAt) {
            const occupiedTime = new Date(table.occupiedAt);
            const elapsedTime = now - occupiedTime;

            if (elapsedTime >= FORTY_FIVE_MINUTES) {
              try {
                const response = await fetch("/api/tables/release", {
                  method: "POST",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify({
                    tableId: table._id,
                    restaurantId: restaurant._id,
                  }),
                });

                const data = await response.json();
                if (data.success) {
                  console.log(
                    `Auto-released table ${table.tableNumber} after 45 minutes`,
                  );
                  loadData(); // Refresh the data to reflect the change
                }
              } catch (error) {
                console.error(
                  `Error auto-releasing table ${table.tableNumber}:`,
                  error,
                );
              }
            }
          }
        }
      } catch (error) {
        console.error("Error in auto-release check:", error);
      }
    }, 60000); // Check every minute

    return () => clearInterval(autoReleaseInterval);
  }, [restaurant, tables]);

  async function loadRestaurant() {
    try {
      const res = await fetch("/api/me/restaurant");
      if (res.ok) {
        const data = await res.json();
        setRestaurant(data);
      }
    } catch (error) {
      console.error("Error loading restaurant:", error);
    }
  }

  async function loadData() {
    try {
      setLoading(true);

      // Load configs
      const configRes = await fetch(
        `/api/admin/tables/config?restaurantId=${restaurant._id}`,
      );
      const configData = await configRes.json();
      if (configData.success) {
        setConfigs(configData.configs);
      }

      // Load tables
      const tablesRes = await fetch(
        `/api/admin/tables?restaurantId=${restaurant._id}`,
      );
      const tablesData = await tablesRes.json();
      if (tablesData.success) {
        setTables(tablesData.tables);
      }
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setLoading(false);
    }
  }

  async function handleSaveConfig(e) {
    e.preventDefault();

    try {
      const response = await fetch("/api/admin/tables/config", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          restaurantId: restaurant._id,
          areaType: configForm.area,
          capacity: configForm.capacity,
          totalTables: configForm.totalTables,
          price: configForm.pricePerTable,
        }),
      });

      const data = await response.json();

      if (data.success) {
        alert(`Configuration saved! ${data.tablesCreated} tables created.`);
        loadData();
        setShowConfigForm(false);
        setConfigForm({
          area: "dine-in",
          capacity: 2,
          totalTables: 10,
          pricePerTable: 30,
        });
      } else {
        alert("Error: " + data.error);
      }
    } catch (error) {
      alert("Error saving configuration: " + error.message);
    }
  }

  async function releaseTable(tableId) {
    if (!confirm("Release this table?")) return;

    try {
      const response = await fetch("/api/tables/release", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          tableId,
          restaurantId: restaurant._id,
        }),
      });

      const data = await response.json();

      if (data.success) {
        alert("Table released successfully");
        loadData();
      } else {
        alert("Error: " + data.error);
      }
    } catch (error) {
      alert("Error releasing table: " + error.message);
    }
  }

  const stats = {
    total: tables.length,
    occupied: tables.filter((t) => t.isOccupied).length,
    available: tables.filter((t) => !t.isOccupied).length,
    dineIn: {
      total: tables.filter((t) => t.area === "dine-in").length,
      occupied: tables.filter((t) => t.area === "dine-in" && t.isOccupied)
        .length,
    },
    foodCourt: {
      total: tables.filter((t) => t.area === "food-court").length,
      occupied: tables.filter((t) => t.area === "food-court" && t.isOccupied)
        .length,
    },
  };

  const occupancyRate =
    stats.total > 0 ? Math.round((stats.occupied / stats.total) * 100) : 0;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />
        <div className="flex items-center justify-center py-20">
          <div className="text-center">
            <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-orange-600 mx-auto mb-4"></div>
            <p className="text-gray-600 dark:text-slate-400">
              Loading tables...
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
      <DashboardHeader />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h1 className="text-3xl font-bold text-gray-900 dark:text-stone-100">
                Table Management
              </h1>
              <p className="text-sm text-gray-500 dark:text-slate-400 mt-1">
                {restaurant?.name}
              </p>
            </div>
            <button
              onClick={() => loadData()}
              className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition"
            >
              <RefreshCw size={18} />
              Refresh
            </button>
          </div>

          {/* Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6">
              <div className="flex items-center justify-between mb-2">
                <span className="text-gray-600 dark:text-slate-400 text-sm font-medium">
                  Total Tables
                </span>
                <Users size={20} className="text-blue-500" />
              </div>
              <p className="text-3xl font-black text-gray-900 dark:text-stone-100">
                {stats.total}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6">
              <div className="flex items-center justify-between mb-2">
                <span className="text-gray-600 dark:text-slate-400 text-sm font-medium">
                  Occupied
                </span>
                <XCircle size={20} className="text-red-500" />
              </div>
              <p className="text-3xl font-black text-gray-900 dark:text-stone-100">
                {stats.occupied}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6">
              <div className="flex items-center justify-between mb-2">
                <span className="text-gray-600 dark:text-slate-400 text-sm font-medium">
                  Available
                </span>
                <CheckCircle size={20} className="text-green-500" />
              </div>
              <p className="text-3xl font-black text-gray-900 dark:text-stone-100">
                {stats.available}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6">
              <div className="flex items-center justify-between mb-2">
                <span className="text-gray-600 dark:text-slate-400 text-sm font-medium">
                  Occupancy
                </span>
                <Clock size={20} className="text-orange-500" />
              </div>
              <p className="text-3xl font-black text-gray-900 dark:text-stone-100">
                {occupancyRate}%
              </p>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm mb-6">
          <div className="flex border-b border-gray-200 dark:border-slate-700">
            <button
              onClick={() => setActiveTab("overview")}
              className={`px-6 py-4 font-semibold transition ${
                activeTab === "overview"
                  ? "text-orange-600 dark:text-orange-400 border-b-2 border-orange-600"
                  : "text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-300"
              }`}
            >
              Overview
            </button>
            <button
              onClick={() => setActiveTab("config")}
              className={`px-6 py-4 font-semibold transition ${
                activeTab === "config"
                  ? "text-orange-600 dark:text-orange-400 border-b-2 border-orange-600"
                  : "text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-300"
              }`}
            >
              Configuration
            </button>
            <button
              onClick={() => setActiveTab("occupied")}
              className={`px-6 py-4 font-semibold transition ${
                activeTab === "occupied"
                  ? "text-orange-600 dark:text-orange-400 border-b-2 border-orange-600"
                  : "text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-300"
              }`}
            >
              Occupied Tables ({stats.occupied})
            </button>
          </div>

          <div className="p-6">
            {/* Overview Tab */}
            {activeTab === "overview" && (
              <div className="space-y-6">
                {/* Dine-In */}
                <div>
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900 dark:text-stone-100 flex items-center gap-2">
                      <span>🍽️</span>
                      Dine-In Tables
                    </h3>
                    <span className="text-sm text-gray-500 dark:text-slate-400">
                      {stats.dineIn.occupied}/{stats.dineIn.total} occupied
                    </span>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-3">
                    {tables
                      .filter((t) => t.area === "dine-in")
                      .sort((a, b) =>
                        a.tableNumber.localeCompare(b.tableNumber),
                      )
                      .map((table) => (
                        <TableCard
                          key={table._id}
                          table={table}
                          onRelease={releaseTable}
                        />
                      ))}
                  </div>
                </div>

                {/* Food Court */}
                <div>
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900 dark:text-stone-100 flex items-center gap-2">
                      <span>🏪</span>
                      Food Court Tables
                    </h3>
                    <span className="text-sm text-gray-500 dark:text-slate-400">
                      {stats.foodCourt.occupied}/{stats.foodCourt.total}{" "}
                      occupied
                    </span>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-3">
                    {tables
                      .filter((t) => t.area === "food-court")
                      .sort((a, b) =>
                        a.tableNumber.localeCompare(b.tableNumber),
                      )
                      .map((table) => (
                        <TableCard
                          key={table._id}
                          table={table}
                          onRelease={releaseTable}
                        />
                      ))}
                  </div>
                </div>
              </div>
            )}

            {/* Configuration Tab */}
            {activeTab === "config" && (
              <div>
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-lg font-bold text-gray-900 dark:text-stone-100">
                    Seating Configuration
                  </h3>
                  <button
                    onClick={() => setShowConfigForm(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition"
                  >
                    <Plus size={18} />
                    Add Configuration
                  </button>
                </div>

                {/* Config Form Modal */}
                {showConfigForm && (
                  <div className="fixed inset-0 bg-black/50 dark:bg-black/70 flex items-center justify-center p-4 z-50">
                    <div className="bg-white dark:bg-slate-800 rounded-xl p-6 max-w-md w-full">
                      <h3 className="text-xl font-bold mb-4 text-gray-900 dark:text-stone-100">
                        Add/Edit Configuration
                      </h3>

                      <form onSubmit={handleSaveConfig} className="space-y-4">
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-2">
                            Area
                          </label>
                          <select
                            value={configForm.area}
                            onChange={(e) =>
                              setConfigForm({
                                ...configForm,
                                area: e.target.value,
                              })
                            }
                            className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-gray-900 dark:text-slate-100 rounded-lg focus:ring-2 focus:ring-orange-500"
                          >
                            <option value="dine-in">Dine-In</option>
                            <option value="food-court">Food Court</option>
                          </select>
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-2">
                            Table Capacity (Persons)
                          </label>
                          <select
                            value={configForm.capacity}
                            onChange={(e) =>
                              setConfigForm({
                                ...configForm,
                                capacity: parseInt(e.target.value),
                              })
                            }
                            className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-gray-900 dark:text-slate-100 rounded-lg focus:ring-2 focus:ring-orange-500"
                          >
                            <option value={2}>2 Persons</option>
                            <option value={4}>4 Persons</option>
                            <option value={6}>6 Persons</option>
                            <option value={8}>8 Persons</option>
                          </select>
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-2">
                            Total Tables
                          </label>
                          <input
                            type="number"
                            min="1"
                            value={configForm.totalTables}
                            onChange={(e) =>
                              setConfigForm({
                                ...configForm,
                                totalTables: parseInt(e.target.value),
                              })
                            }
                            className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-gray-900 dark:text-slate-100 rounded-lg focus:ring-2 focus:ring-orange-500"
                          />
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-2">
                            Price Per Table ($)
                          </label>
                          <input
                            type="number"
                            min="0"
                            step="0.01"
                            value={configForm.pricePerTable}
                            onChange={(e) =>
                              setConfigForm({
                                ...configForm,
                                pricePerTable: parseFloat(e.target.value),
                              })
                            }
                            className="w-full px-3 py-2 border border-gray-300 dark:border-slate-600 bg-white dark:bg-slate-700 text-gray-900 dark:text-slate-100 rounded-lg focus:ring-2 focus:ring-orange-500"
                          />
                        </div>

                        <div className="flex gap-3">
                          <button
                            type="button"
                            onClick={() => setShowConfigForm(false)}
                            className="flex-1 px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition text-gray-700 dark:text-slate-300"
                          >
                            Cancel
                          </button>
                          <button
                            type="submit"
                            className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition"
                          >
                            Save
                          </button>
                        </div>
                      </form>
                    </div>
                  </div>
                )}

                {/* Existing Configs */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {configs.map((config) => (
                    <div
                      key={config._id}
                      className="bg-gray-50 dark:bg-slate-700/40 rounded-lg p-6 border border-gray-100 dark:border-slate-700"
                    >
                      <div className="flex items-start justify-between mb-4">
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <Users
                              size={18}
                              className="text-orange-600 dark:text-orange-400"
                            />
                            <h4 className="font-bold text-gray-900 dark:text-stone-100">
                              Table for {config.capacity}
                            </h4>
                          </div>
                          <p className="text-sm text-gray-500 dark:text-slate-400 capitalize">
                            {config.area}
                          </p>
                        </div>
                        <span
                          className={`px-2 py-1 rounded-full text-xs font-semibold ${
                            config.isActive
                              ? "bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-400"
                              : "bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400"
                          }`}
                        >
                          {config.isActive ? "Active" : "Inactive"}
                        </span>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                            Total Tables
                          </p>
                          <p className="text-xl font-bold text-gray-900 dark:text-stone-100">
                            {config.totalTables}
                          </p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                            Price
                          </p>
                          <p className="text-xl font-bold text-green-600 dark:text-green-400">
                            ${config.pricePerTable.toFixed(2)}
                          </p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Occupied Tables Tab */}
            {activeTab === "occupied" && (
              <div>
                <div className="space-y-3">
                  {tables
                    .filter((t) => t.isOccupied)
                    .map((table) => (
                      <div
                        key={table._id}
                        className="flex items-center justify-between p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/40 rounded-lg"
                      >
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-red-100 dark:bg-red-900/40 rounded-full flex items-center justify-center">
                            <span className="font-bold text-red-700 dark:text-red-400">
                              {table.tableNumber}
                            </span>
                          </div>

                          <div>
                            <p className="font-bold text-gray-900 dark:text-stone-100">
                              Table {table.tableNumber}
                            </p>
                            <div className="flex items-center gap-3 text-sm text-gray-600 dark:text-slate-400">
                              <span className="flex items-center gap-1">
                                <Users size={14} />
                                {table.capacity} persons
                              </span>
                              <span className="flex items-center gap-1">
                                <MapPin size={14} />
                                {table.area}
                              </span>
                              {table.occupiedAt && (
                                <span className="flex items-center gap-1">
                                  <Clock size={14} />
                                  {new Date(
                                    table.occupiedAt,
                                  ).toLocaleTimeString()}
                                </span>
                              )}
                            </div>
                          </div>
                        </div>

                        <button
                          onClick={() => releaseTable(table._id)}
                          className="px-4 py-2 bg-white dark:bg-slate-800 border border-red-300 dark:border-red-900/40 text-red-700 dark:text-red-400 rounded-lg hover:bg-red-50 dark:hover:bg-slate-700 transition font-semibold text-sm"
                        >
                          Release Table
                        </button>
                      </div>
                    ))}

                  {tables.filter((t) => t.isOccupied).length === 0 && (
                    <div className="text-center py-12">
                      <CheckCircle
                        size={48}
                        className="text-green-500 mx-auto mb-4"
                      />
                      <h3 className="text-lg font-bold text-gray-900 dark:text-stone-100 mb-2">
                        All Tables Available
                      </h3>
                      <p className="text-gray-600 dark:text-slate-400">
                        No tables are currently occupied
                      </p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// Table Card Component
function TableCard({ table, onRelease }) {
  return (
    <div
      className={`relative p-4 rounded-lg border-2 transition ${
        table.isOccupied
          ? "bg-red-50 dark:bg-red-900/20 border-red-300 dark:border-red-900/40"
          : "bg-green-50 dark:bg-green-900/20 border-green-300 dark:border-green-900/40"
      }`}
    >
      <div className="text-center">
        <p className="text-lg font-black text-gray-900 dark:text-stone-100 mb-1">
          {table.tableNumber}
        </p>
        <div className="flex items-center justify-center gap-1 text-xs text-gray-600 dark:text-slate-400">
          <Users size={12} />
          <span>{table.capacity}</span>
        </div>
      </div>

      {table.isOccupied && (
        <button
          onClick={() => onRelease(table._id)}
          className="absolute top-2 right-2 w-6 h-6 bg-red-600 dark:bg-red-900/60 text-white rounded-full flex items-center justify-center hover:bg-red-700 dark:hover:bg-red-900 transition"
          title="Release table"
        >
          <XCircle size={14} />
        </button>
      )}
    </div>
  );
}

"use client";

import ProtectedAdminRoute from "@/components/ProtectedAdminRoute";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useState, useEffect } from "react";
import {
  Activity,
  Search,
  RefreshCw,
  Filter,
  Clock,
  User,
  Shield,
  Settings,
  Database,
} from "lucide-react";
import { toast } from "sonner";

const ACTIVITY_TYPES = {
  role_change: {
    label: "Role Changed",
    icon: Shield,
    color: "text-purple-600",
  },
  user_action: { label: "User Action", icon: User, color: "text-blue-600" },
  settings_update: {
    label: "Settings Updated",
    icon: Settings,
    color: "text-orange-600",
  },
  data_change: { label: "Data Changed", icon: Database, color: "text-red-600" },
  login: { label: "Login", icon: User, color: "text-green-600" },
};

export default function AdminActivityPage() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("all");

  useEffect(() => {
    loadLogs();
  }, []);

  async function loadLogs() {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      params.append("limit", "100");
      if (typeFilter !== "all") params.append("type", typeFilter);

      const res = await fetch(`/api/admin/activity/logs?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load logs");

      const data = await res.json();
      setLogs(data.logs || []);
    } catch (error) {
      console.error("Error loading logs:", error);
      toast.error("Failed to load activity logs");
    } finally {
      setLoading(false);
    }
  }

  const filteredLogs = logs.filter((log) => {
    if (searchTerm.toLowerCase()) {
      return (
        log.action?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.type?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.userId?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    return true;
  });

  const getActivityColor = (type) => {
    switch (type) {
      case "role_change":
        return "bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-900/50";
      case "settings_update":
        return "bg-orange-50 dark:bg-orange-900/20 border-orange-200 dark:border-orange-900/50";
      case "data_change":
        return "bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-900/50";
      case "login":
        return "bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-900/50";
      default:
        return "bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-900/50";
    }
  };

  return (
    <ProtectedAdminRoute requiredRole="admin">
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Header */}
          <div className="mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-4xl font-bold text-gray-900 dark:text-white mb-2">
                  Activity Log
                </h1>
                <p className="text-gray-600 dark:text-gray-400">
                  Track admin actions and system events
                </p>
              </div>
              <button
                onClick={loadLogs}
                className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition"
              >
                <RefreshCw size={18} />
                Refresh
              </button>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3">
              <div className="flex-1 relative">
                <Search
                  size={18}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"
                />
                <input
                  type="text"
                  placeholder="Search by action, type, or user ID..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <select
                value={typeFilter}
                onChange={(e) => setTypeFilter(e.target.value)}
                className="px-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Types</option>
                <option value="role_change">Role Changed</option>
                <option value="settings_update">Settings Updated</option>
                <option value="user_action">User Action</option>
                <option value="data_change">Data Changed</option>
              </select>
            </div>
          </div>

          {/* Activity Timeline */}
          {loading ? (
            <div className="flex items-center justify-center py-20">
              <div className="text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
                <p className="text-gray-600 dark:text-gray-400">
                  Loading logs...
                </p>
              </div>
            </div>
          ) : filteredLogs.length === 0 ? (
            <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-xl">
              <Activity
                size={48}
                className="text-gray-300 dark:text-gray-600 mx-auto mb-4"
              />
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                No activities found
              </h3>
              <p className="text-gray-600 dark:text-gray-400">
                Try adjusting your filters
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {filteredLogs.map((log) => {
                const activityType =
                  ACTIVITY_TYPES[log.type] || ACTIVITY_TYPES.user_action;
                const IconComponent = activityType.icon;

                return (
                  <div
                    key={log._id}
                    className={`border rounded-lg p-4 transition ${getActivityColor(log.type)}`}
                  >
                    <div className="flex items-start gap-4">
                      {/* Icon */}
                      <div className="flex-shrink-0 mt-1">
                        <div
                          className={`p-2 rounded-lg bg-white dark:bg-slate-800/50`}
                        >
                          <IconComponent
                            size={20}
                            className={activityType.color}
                          />
                        </div>
                      </div>

                      {/* Content */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between mb-1">
                          <h4 className="font-semibold text-gray-900 dark:text-white">
                            {activityType.label}
                          </h4>
                          <span className="text-xs text-gray-500 dark:text-gray-400 whitespace-nowrap ml-4">
                            {log.createdAt
                              ? new Date(log.createdAt).toLocaleString()
                              : "N/A"}
                          </span>
                        </div>

                        <p className="text-sm text-gray-600 dark:text-gray-300 mb-2">
                          {log.action}
                        </p>

                        {/* Details */}
                        <div className="flex flex-wrap items-center gap-4 text-xs text-gray-500 dark:text-gray-400">
                          {log.userId && (
                            <span>
                              <strong>User:</strong>{" "}
                              {log.userId.substring(0, 8)}...
                            </span>
                          )}
                          {log.targetType && (
                            <span>
                              <strong>Target:</strong> {log.targetType}
                            </span>
                          )}
                          {log.ipAddress && log.ipAddress !== "unknown" && (
                            <span>
                              <strong>IP:</strong> {log.ipAddress}
                            </span>
                          )}
                        </div>

                        {/* Additional Details */}
                        {log.details && (
                          <div className="mt-2 p-2 bg-white dark:bg-slate-800/50 rounded text-xs text-gray-600 dark:text-gray-400 font-mono">
                            {typeof log.details === "object"
                              ? JSON.stringify(log.details)
                              : log.details}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Stats */}
          {!loading && logs.length > 0 && (
            <div className="mt-8 bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6 border border-gray-200 dark:border-slate-700">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                Activity Summary
              </h3>
              <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                {Object.entries(ACTIVITY_TYPES).map(([key, config]) => {
                  const count = logs.filter((l) => l.type === key).length;
                  const IconComponent = config.icon;
                  return (
                    <div
                      key={key}
                      className="p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg"
                    >
                      <div className="flex items-center gap-2 mb-2">
                        <IconComponent size={16} className={config.color} />
                        <p className="text-xs text-gray-600 dark:text-gray-400 font-medium">
                          {config.label}
                        </p>
                      </div>
                      <p className="text-2xl font-bold text-gray-900 dark:text-white">
                        {count}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </ProtectedAdminRoute>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import {
  Search,
  Filter,
  ChevronDown,
  Download,
  Loader2,
  Eye,
  Edit2,
  MoreVertical,
} from "lucide-react";

const PLANS = [
  { id: "all", name: "All Plans", color: "gray" },
  { id: "starter", name: "Starter Plan", color: "blue" },
  { id: "professional", name: "Professional Plan", color: "green" },
  { id: "enterprise", name: "Enterprise Plan", color: "purple" },
];

const STATUSES = [
  { id: "active", label: "Active", color: "green" },
  { id: "pending", label: "Pending", color: "yellow" },
  { id: "inactive", label: "Inactive", color: "red" },
];

export default function RestaurantPlansPage() {
  const [restaurants, setRestaurants] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedPlan, setSelectedPlan] = useState("all");
  const [page, setPage] = useState(1);
  const [pagination, setPagination] = useState(null);
  const [sortBy, setSortBy] = useState("name");

  const fetchData = async () => {
    setLoading(true);
    try {
      const query = new URLSearchParams({
        plan: selectedPlan,
        sortBy,
        page,
        limit: 20,
      });

      const res = await fetch(`/api/admin/restaurants-plans?${query}`);
      const data = await res.json();

      if (!res.ok) throw new Error(data.error);

      setRestaurants(data.data);
      setPagination(data.pagination);
    } catch (err) {
      console.error("Error fetching data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [selectedPlan, sortBy, page]);

  const filteredRestaurants = restaurants.filter(
    (r) =>
      r.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.email.toLowerCase().includes(searchTerm.toLowerCase()),
  );

  const getPlanColor = (planId) => {
    const plan = PLANS.find((p) => p.id === planId);
    const colorMap = {
      blue: "bg-blue-100 dark:bg-blue-900 text-blue-800 dark:text-blue-200",
      green:
        "bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200",
      purple:
        "bg-purple-100 dark:bg-purple-900 text-purple-800 dark:text-purple-200",
    };
    return colorMap[plan?.color] || colorMap.blue;
  };

  const getStatusColor = (status) => {
    const statusObj = STATUSES.find((s) => s.id === status);
    const colorMap = {
      green:
        "bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200",
      yellow:
        "bg-yellow-100 dark:bg-yellow-900 text-yellow-800 dark:text-yellow-200",
      red: "bg-red-100 dark:bg-red-900 text-red-800 dark:text-red-200",
    };
    return colorMap[statusObj?.color] || colorMap.gray;
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
            Restaurant Plans
          </h1>
          <p className="text-gray-600 dark:text-gray-400">
            View and manage all restaurants and their subscription plans
          </p>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
          {[
            {
              label: "Total Restaurants",
              value: pagination?.total || 0,
              color: "bg-blue-50 dark:bg-blue-900/20",
            },
            {
              label: "Starter Plans",
              value: restaurants.filter((r) => r.planId === "starter").length,
              color: "bg-green-50 dark:bg-green-900/20",
            },
            {
              label: "Professional Plans",
              value: restaurants.filter((r) => r.planId === "professional")
                .length,
              color: "bg-purple-50 dark:bg-purple-900/20",
            },
            {
              label: "Enterprise Plans",
              value: restaurants.filter((r) => r.planId === "enterprise")
                .length,
              color: "bg-orange-50 dark:bg-orange-900/20",
            },
          ].map((stat, i) => (
            <div
              key={i}
              className={`${stat.color} rounded-lg p-6 border border-gray-200 dark:border-gray-700`}
            >
              <p className="text-sm font-medium text-gray-600 dark:text-gray-400">
                {stat.label}
              </p>
              <p className="text-2xl font-bold text-gray-900 dark:text-white mt-2">
                {stat.value}
              </p>
            </div>
          ))}
        </div>

        {/* Filters */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm p-6 mb-8">
          <div className="flex flex-col md:flex-row gap-4">
            {/* Search */}
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
                <input
                  type="text"
                  placeholder="Search by restaurant name or email..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg
                           bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                           focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>

            {/* Plan Filter */}
            <div className="flex gap-4">
              <select
                value={selectedPlan}
                onChange={(e) => {
                  setSelectedPlan(e.target.value);
                  setPage(1);
                }}
                className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg
                         bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                         focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                {PLANS.map((plan) => (
                  <option key={plan.id} value={plan.id}>
                    {plan.name}
                  </option>
                ))}
              </select>

              <select
                value={sortBy}
                onChange={(e) => {
                  setSortBy(e.target.value);
                  setPage(1);
                }}
                className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg
                         bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                         focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="name">Sort by Name</option>
                <option value="planPrice">Sort by Price</option>
                <option value="createdAt">Sort by Date</option>
              </select>

              <button className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition">
                <Download className="w-4 h-4" />
                Export CSV
              </button>
            </div>
          </div>
        </div>

        {/* Table */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
          {loading ? (
            <div className="flex items-center justify-center h-64">
              <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 dark:bg-gray-700 border-b border-gray-200 dark:border-gray-600">
                  <tr>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Restaurant
                    </th>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Plan
                    </th>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Price
                    </th>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Status
                    </th>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Renewal Date
                    </th>
                    <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {filteredRestaurants.map((restaurant) => (
                    <tr
                      key={restaurant.id}
                      className="hover:bg-gray-50 dark:hover:bg-gray-700 transition"
                    >
                      <td className="px-6 py-4">
                        <div>
                          <p className="font-medium text-gray-900 dark:text-white">
                            {restaurant.name}
                          </p>
                          <p className="text-sm text-gray-600 dark:text-gray-400">
                            {restaurant.email}
                          </p>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`px-3 py-1 rounded-full text-sm font-medium ${getPlanColor(
                            restaurant.planId,
                          )}`}
                        >
                          {restaurant.planName}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <p className="font-semibold text-gray-900 dark:text-white">
                          ${restaurant.planPrice}/mo
                        </p>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(
                            restaurant.planStatus,
                          )}`}
                        >
                          {restaurant.planStatus === "active"
                            ? "Active"
                            : "Pending"}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-400">
                        {restaurant.planRenewalDate
                          ? new Date(
                              restaurant.planRenewalDate,
                            ).toLocaleDateString()
                          : "-"}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <Link
                            href={`/dashboard/admin/restaurants-plans/${restaurant.id}`}
                            className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition"
                          >
                            <Eye className="w-4 h-4 text-gray-600 dark:text-gray-400" />
                          </Link>
                          <button className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition">
                            <Edit2 className="w-4 h-4 text-gray-600 dark:text-gray-400" />
                          </button>
                          <button className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition">
                            <MoreVertical className="w-4 h-4 text-gray-600 dark:text-gray-400" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {pagination && pagination.pages > 1 && (
            <div className="px-6 py-4 border-t border-gray-200 dark:border-gray-700 flex items-center justify-between">
              <p className="text-sm text-gray-600 dark:text-gray-400">
                Page {page} of {pagination.pages}
              </p>
              <div className="flex gap-2">
                <button
                  onClick={() => setPage(Math.max(1, page - 1))}
                  disabled={page === 1}
                  className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg
                           hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-50"
                >
                  Previous
                </button>
                <button
                  onClick={() => setPage(Math.min(pagination.pages, page + 1))}
                  disabled={page === pagination.pages}
                  className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg
                           hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-50"
                >
                  Next
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import ProtectedAdminRoute from "@/components/ProtectedAdminRoute";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useState, useEffect } from "react";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import {
  ArrowLeft,
  Building2,
  ShoppingBag,
  DollarSign,
  Users,
  MapPin,
  Mail,
  Phone,
  RefreshCw,
  Copy,
} from "lucide-react";
import { toast } from "sonner";

export default function AdminRestaurantDetailPage() {
  const params = useParams();
  const router = useRouter();
  const restaurantId = params.id;

  const [restaurant, setRestaurant] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadRestaurant();
  }, [restaurantId]);

  async function loadRestaurant() {
    try {
      setLoading(true);
      console.log("📝 Loading restaurant:", restaurantId);

      const res = await fetch(`/api/admin/restaurants/${restaurantId}`);

      console.log("📊 Response status:", res.status);

      if (!res.ok) {
        const errorData = await res.json();
        console.error("❌ API Error:", errorData);
        throw new Error(errorData.error || "Failed to load restaurant");
      }

      const data = await res.json();
      console.log("✅ Restaurant loaded:", data.restaurant?.name);
      setRestaurant(data.restaurant);
    } catch (error) {
      console.error("🚨 Error loading restaurant:", error.message);
      toast.error(`Failed to load restaurant: ${error.message}`);
      router.push("/dashboard/admin/restaurants");
    } finally {
      setLoading(false);
    }
  }

  const handleCopy = async (text) => {
    await navigator.clipboard.writeText(text);
    toast.success("Copied to clipboard!");
  };

  if (loading) {
    return (
      <ProtectedAdminRoute requiredRole="admin">
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
          <DashboardHeader />
          <div className="flex items-center justify-center py-20">
            <div className="text-center">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
              <p className="text-gray-600 dark:text-gray-400">
                Loading restaurant...
              </p>
            </div>
          </div>
        </div>
      </ProtectedAdminRoute>
    );
  }

  if (!restaurant) {
    return (
      <ProtectedAdminRoute requiredRole="admin">
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
          <DashboardHeader />
          <div className="max-w-2xl mx-auto px-4 sm:px-6 lg:px-8 py-20">
            <div className="bg-white dark:bg-slate-800 rounded-xl p-8 text-center border border-red-200 dark:border-red-900">
              <div className="text-5xl mb-4">❌</div>
              <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
                Restaurant Not Found
              </h1>
              <p className="text-gray-600 dark:text-gray-400 mb-2">
                Unable to load restaurant with ID:
              </p>
              <code className="block bg-gray-100 dark:bg-slate-900 p-3 rounded mb-6 text-sm text-gray-800 dark:text-gray-200 break-all">
                {restaurantId}
              </code>
              <p className="text-gray-600 dark:text-gray-400 mb-6">
                This restaurant doesn&apos;t exist in the database. This ID may be
                invalid or the restaurant may have been deleted.
              </p>
              <Link
                href="/dashboard/admin/restaurants"
                className="inline-flex items-center gap-2 px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition"
              >
                <ArrowLeft size={20} />
                Back to Restaurants
              </Link>
            </div>
          </div>
        </div>
      </ProtectedAdminRoute>
    );
  }

  const stats = restaurant.stats || {};

  return (
    <ProtectedAdminRoute requiredRole="admin">
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Header */}
          <div className="mb-8">
            <Link
              href="/dashboard/admin/restaurants"
              className="flex items-center gap-2 text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 mb-6"
            >
              <ArrowLeft size={18} />
              Back to Restaurants
            </Link>

            <div className="flex items-center justify-between">
              <div className="flex items-center gap-4">
                {restaurant.logo ? (
                  <img
                    src={restaurant.logo}
                    alt={restaurant.name}
                    className="w-16 h-16 rounded-lg object-cover"
                  />
                ) : (
                  <div className="w-16 h-16 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                    <Building2 size={32} className="text-blue-600" />
                  </div>
                )}
                <div>
                  <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
                    {restaurant.name}
                  </h1>
                  <p className="text-gray-600 dark:text-gray-400">
                    {restaurant.slug}
                  </p>
                </div>
              </div>

              <button
                onClick={loadRestaurant}
                className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition"
              >
                <RefreshCw size={18} />
                Refresh
              </button>
            </div>
          </div>

          {/* Status Badge */}
          <div className="mb-6">
            <span
              className={`px-4 py-2 rounded-full text-sm font-semibold ${
                restaurant.isActive
                  ? "bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400"
                  : "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-400"
              }`}
            >
              {restaurant.isActive ? "✓ Active" : "○ Inactive"}
            </span>
          </div>

          {/* Stats Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <ShoppingBag size={24} className="text-emerald-600 mb-2" />
              <p className="text-sm text-gray-600 dark:text-gray-400">
                Total Orders
              </p>
              <p className="text-3xl font-bold text-gray-900 dark:text-white mt-1">
                {stats.ordersCount || 0}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <DollarSign size={24} className="text-green-600 mb-2" />
              <p className="text-sm text-gray-600 dark:text-gray-400">
                Revenue
              </p>
              <p className="text-3xl font-bold text-green-600 dark:text-green-400 mt-1">
                ${(stats.totalRevenue || 0).toFixed(2)}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <DollarSign size={24} className="text-blue-600 mb-2" />
              <p className="text-sm text-gray-600 dark:text-gray-400">
                Avg Order Value
              </p>
              <p className="text-3xl font-bold text-gray-900 dark:text-white mt-1">
                ${(stats.avgOrderValue || 0).toFixed(2)}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <Users size={24} className="text-purple-600 mb-2" />
              <p className="text-sm text-gray-600 dark:text-gray-400">Tables</p>
              <p className="text-3xl font-bold text-gray-900 dark:text-white mt-1">
                {stats.tablesCount || 0}
              </p>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <Building2 size={24} className="text-orange-600 mb-2" />
              <p className="text-sm text-gray-600 dark:text-gray-400">Menus</p>
              <p className="text-3xl font-bold text-gray-900 dark:text-white mt-1">
                {stats.menusCount || 0}
              </p>
            </div>
          </div>

          {/* Restaurant Details */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            {/* Contact Info */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
                Contact Information
              </h3>

              <div className="space-y-4">
                {/* Email */}
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <Mail
                      size={18}
                      className="text-gray-600 dark:text-gray-400"
                    />
                    <span className="text-sm text-gray-600 dark:text-gray-400">
                      Email
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <p className="text-gray-900 dark:text-white break-all">
                      {restaurant.email || "N/A"}
                    </p>
                    {restaurant.email && (
                      <button
                        onClick={() => handleCopy(restaurant.email)}
                        className="p-1 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                      >
                        <Copy size={16} className="text-gray-600" />
                      </button>
                    )}
                  </div>
                </div>

                {/* Phone */}
                {restaurant.phone && (
                  <div>
                    <div className="flex items-center gap-2 mb-2">
                      <Phone
                        size={18}
                        className="text-gray-600 dark:text-gray-400"
                      />
                      <span className="text-sm text-gray-600 dark:text-gray-400">
                        Phone
                      </span>
                    </div>
                    <p className="text-gray-900 dark:text-white ml-6">
                      {restaurant.phone}
                    </p>
                  </div>
                )}

                {/* Address */}
                {restaurant.address && (
                  <div>
                    <div className="flex items-center gap-2 mb-2">
                      <MapPin
                        size={18}
                        className="text-gray-600 dark:text-gray-400"
                      />
                      <span className="text-sm text-gray-600 dark:text-gray-400">
                        Address
                      </span>
                    </div>
                    <p className="text-gray-900 dark:text-white ml-6">
                      {restaurant.address}
                    </p>
                  </div>
                )}
              </div>
            </div>

            {/* URLs */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
                URLs
              </h3>

              <div className="space-y-4">
                {/* Public URL */}
                <div>
                  <label className="block text-sm font-medium text-gray-600 dark:text-gray-400 mb-2">
                    Public Menu URL
                  </label>
                  <div className="flex items-center gap-2">
                    <input
                      type="text"
                      value={restaurant.publicUrl || ""}
                      readOnly
                      className="flex-1 px-3 py-2 bg-gray-50 dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg text-gray-900 dark:text-white text-sm"
                    />
                    {restaurant.publicUrl && (
                      <button
                        onClick={() => handleCopy(restaurant.publicUrl)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                      >
                        <Copy size={18} className="text-gray-600" />
                      </button>
                    )}
                  </div>
                </div>

                {/* Slug */}
                <div>
                  <label className="block text-sm font-medium text-gray-600 dark:text-gray-400 mb-2">
                    Restaurant Slug
                  </label>
                  <input
                    type="text"
                    value={restaurant.slug || ""}
                    readOnly
                    className="w-full px-3 py-2 bg-gray-50 dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg text-gray-900 dark:text-white text-sm"
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Additional Info */}
          <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
              Additional Information
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Owner ID */}
              <div>
                <label className="block text-sm font-medium text-gray-600 dark:text-gray-400 mb-2">
                  Owner ID
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="text"
                    value={restaurant.ownerId?.toString() || ""}
                    readOnly
                    className="flex-1 px-3 py-2 bg-gray-50 dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg text-gray-900 dark:text-white text-sm font-mono"
                  />
                  {restaurant.ownerId && (
                    <button
                      onClick={() => handleCopy(restaurant.ownerId.toString())}
                      className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                    >
                      <Copy size={16} className="text-gray-600" />
                    </button>
                  )}
                </div>
              </div>

              {/* Created Date */}
              <div>
                <label className="block text-sm font-medium text-gray-600 dark:text-gray-400 mb-2">
                  Created
                </label>
                <input
                  type="text"
                  value={
                    restaurant.createdAt
                      ? new Date(restaurant.createdAt).toLocaleString()
                      : "N/A"
                  }
                  readOnly
                  className="w-full px-3 py-2 bg-gray-50 dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg text-gray-900 dark:text-white text-sm"
                />
              </div>

              {/* Description */}
              {restaurant.description && (
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-600 dark:text-gray-400 mb-2">
                    Description
                  </label>
                  <textarea
                    value={restaurant.description}
                    readOnly
                    className="w-full px-3 py-2 bg-gray-50 dark:bg-slate-700 border border-gray-300 dark:border-slate-600 rounded-lg text-gray-900 dark:text-white text-sm h-24"
                  />
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </ProtectedAdminRoute>
  );
}

"use client";

import ProtectedAdminRoute from "@/components/ProtectedAdminRoute";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useState, useEffect } from "react";
import {
  Search,
  Filter,
  ChevronRight,
  Eye,
  Toggle2,
  Trash2,
  MoreVertical,
  RefreshCw,
  Building2,
} from "lucide-react";
import Link from "next/link";
import { toast } from "sonner";

export default function AdminRestaurantsPage() {
  const [restaurants, setRestaurants] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [sortBy, setSortBy] = useState("newest");

  useEffect(() => {
    loadRestaurants();
  }, []);

  async function loadRestaurants() {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (searchTerm) params.append("search", searchTerm);
      if (statusFilter !== "all") params.append("status", statusFilter);

      console.log("📝 Loading restaurants with params:", params.toString());

      const res = await fetch(
        `/api/admin/restaurants/list?${params.toString()}`,
      );

      console.log("📊 API Response status:", res.status);

      if (!res.ok) {
        throw new Error("Failed to load restaurants");
      }

      const data = await res.json();
      console.log(
        `✅ Loaded ${data.restaurants?.length} restaurants:`,
        data.restaurants?.map((r) => r.name),
      );

      // Sort restaurants
      let sorted = [...(data.restaurants || [])];
      if (sortBy === "newest") {
        sorted.sort(
          (a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0),
        );
      } else if (sortBy === "oldest") {
        sorted.sort(
          (a, b) => new Date(a.createdAt || 0) - new Date(b.createdAt || 0),
        );
      } else if (sortBy === "revenue") {
        sorted.sort((a, b) => (b.totalRevenue || 0) - (a.totalRevenue || 0));
      }

      setRestaurants(sorted);
    } catch (error) {
      console.error("Error loading restaurants:", error);
      toast.error("Failed to load restaurants");
    } finally {
      setLoading(false);
    }
  }

  const handleSeedRestaurants = async () => {
    try {
      const res = await fetch("/api/admin/restaurants/seed", {
        method: "POST",
      });
      const data = await res.json();
      if (data.success) {
        toast.success(`Created ${data.restaurants.length} sample restaurants`);
        loadRestaurants();
      } else {
        toast.error(data.error || "Failed to seed restaurants");
      }
    } catch (error) {
      console.error("Error seeding restaurants:", error);
      toast.error("Failed to seed restaurants");
    }
  };

  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleFilterChange = (e) => {
    setStatusFilter(e.target.value);
  };

  const handleRefresh = () => {
    loadRestaurants();
    toast.success("Restaurants refreshed");
  };

  // Filtered data based on search
  const filteredRestaurants = restaurants.filter((restaurant) => {
    if (searchTerm.toLowerCase()) {
      return (
        restaurant.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        restaurant.email?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    return true;
  });

  return (
    <ProtectedAdminRoute requiredRole="admin">
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Header */}
          <div className="mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-4xl font-bold text-gray-900 dark:text-white mb-2">
                  Manage Restaurants
                </h1>
                <p className="text-gray-600 dark:text-gray-400">
                  {filteredRestaurants.length} restaurant
                  {filteredRestaurants.length !== 1 ? "s" : ""} on the platform
                </p>
              </div>
              <button
                onClick={handleRefresh}
                className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition"
              >
                <RefreshCw size={18} />
                Refresh
              </button>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3">
              {/* Search */}
              <div className="flex-1 relative">
                <Search
                  size={18}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"
                />
                <input
                  type="text"
                  placeholder="Search by name or email..."
                  value={searchTerm}
                  onChange={handleSearch}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:ring-2 focus:ring-blue-500"
                />
              </div>

              {/* Status Filter */}
              <select
                value={statusFilter}
                onChange={handleFilterChange}
                className="px-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Status</option>
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
              </select>

              {/* Sort */}
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="px-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
              >
                <option value="newest">Newest First</option>
                <option value="oldest">Oldest First</option>
                <option value="revenue">By Revenue</option>
              </select>
            </div>
          </div>

          {/* Restaurants Table */}
          {loading ? (
            <div className="flex items-center justify-center py-20">
              <div className="text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
                <p className="text-gray-600 dark:text-gray-400">
                  Loading restaurants...
                </p>
              </div>
            </div>
          ) : filteredRestaurants.length === 0 ? (
            <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-xl">
              <Building2
                size={48}
                className="text-gray-300 dark:text-gray-600 mx-auto mb-4"
              />
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                No restaurants found
              </h3>
              <p className="text-gray-600 dark:text-gray-400 mb-6">
                {searchTerm || statusFilter !== "all"
                  ? "Try adjusting your search or filters"
                  : "Create your first restaurant or load sample data"}
              </p>
              {restaurants.length === 0 &&
                !searchTerm &&
                statusFilter === "all" && (
                  <button
                    onClick={handleSeedRestaurants}
                    className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition"
                  >
                    📊 Load Sample Restaurants
                  </button>
                )}
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm overflow-hidden border border-gray-200 dark:border-slate-700">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50 dark:bg-slate-700/50 border-b border-gray-200 dark:border-slate-700">
                    <tr>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Restaurant
                      </th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Owner
                      </th>
                      <th className="px-6 py-4 text-right text-sm font-semibold text-gray-900 dark:text-white">
                        Orders
                      </th>
                      <th className="px-6 py-4 text-right text-sm font-semibold text-gray-900 dark:text-white">
                        Revenue
                      </th>
                      <th className="px-6 py-4 text-center text-sm font-semibold text-gray-900 dark:text-white">
                        Status
                      </th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Joined
                      </th>
                      <th className="px-6 py-4 text-right text-sm font-semibold text-gray-900 dark:text-white">
                        Actions
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
                    {filteredRestaurants.map((restaurant) => (
                      <tr
                        key={restaurant._id}
                        className="hover:bg-gray-50 dark:hover:bg-slate-700/50 transition"
                      >
                        {/* Restaurant Name */}
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            {restaurant.logo ? (
                              <img
                                src={restaurant.logo}
                                alt={restaurant.name}
                                className="w-10 h-10 rounded-lg object-cover"
                              />
                            ) : (
                              <div className="w-10 h-10 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                                <Building2
                                  size={20}
                                  className="text-blue-600"
                                />
                              </div>
                            )}
                            <div>
                              <p className="font-semibold text-gray-900 dark:text-white">
                                {restaurant.name}
                              </p>
                              <p className="text-xs text-gray-500 dark:text-gray-400">
                                {restaurant.slug}
                              </p>
                            </div>
                          </div>
                        </td>

                        {/* Owner Email */}
                        <td className="px-6 py-4">
                          <p className="text-sm text-gray-600 dark:text-gray-300">
                            {restaurant.ownerEmail || "N/A"}
                          </p>
                        </td>

                        {/* Orders Count */}
                        <td className="px-6 py-4 text-right">
                          <p className="text-sm font-semibold text-gray-900 dark:text-white">
                            {restaurant.ordersCount || 0}
                          </p>
                        </td>

                        {/* Revenue */}
                        <td className="px-6 py-4 text-right">
                          <p className="text-sm font-semibold text-green-600 dark:text-green-400">
                            ${(restaurant.totalRevenue || 0).toFixed(2)}
                          </p>
                        </td>

                        {/* Status */}
                        <td className="px-6 py-4 text-center">
                          <span
                            className={`px-3 py-1 rounded-full text-xs font-semibold ${
                              restaurant.isActive
                                ? "bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400"
                                : "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-400"
                            }`}
                          >
                            {restaurant.isActive ? "Active" : "Inactive"}
                          </span>
                        </td>

                        {/* Joined Date */}
                        <td className="px-6 py-4">
                          <p className="text-sm text-gray-600 dark:text-gray-400">
                            {restaurant.createdAt
                              ? new Date(
                                  restaurant.createdAt,
                                ).toLocaleDateString()
                              : "N/A"}
                          </p>
                        </td>

                        {/* Actions */}
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-2">
                            <Link
                              href={`/dashboard/admin/restaurants/${restaurant._id}`}
                              className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition"
                              title="View Details"
                            >
                              <Eye
                                size={18}
                                className="text-gray-600 dark:text-gray-400"
                              />
                            </Link>
                            <button
                              className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition"
                              title="View More"
                            >
                              <MoreVertical
                                size={18}
                                className="text-gray-600 dark:text-gray-400"
                              />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Stats Summary */}
          {!loading && filteredRestaurants.length > 0 && (
            <div className="mt-8 bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6 border border-gray-200 dark:border-slate-700">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                Summary
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
                    Total Restaurants
                  </p>
                  <p className="text-3xl font-bold text-gray-900 dark:text-white">
                    {filteredRestaurants.length}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
                    Active
                  </p>
                  <p className="text-3xl font-bold text-green-600 dark:text-green-400">
                    {filteredRestaurants.filter((r) => r.isActive).length}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
                    Total Orders
                  </p>
                  <p className="text-3xl font-bold text-blue-600 dark:text-blue-400">
                    {filteredRestaurants.reduce(
                      (sum, r) => sum + (r.ordersCount || 0),
                      0,
                    )}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
                    Total Revenue
                  </p>
                  <p className="text-3xl font-bold text-emerald-600 dark:text-emerald-400">
                    $
                    {filteredRestaurants
                      .reduce((sum, r) => sum + (r.totalRevenue || 0), 0)
                      .toFixed(2)}
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </ProtectedAdminRoute>
  );
}

"use client";

import ProtectedAdminRoute from "@/components/ProtectedAdminRoute";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useState, useEffect } from "react";
import {
  Settings,
  Save,
  RefreshCw,
  AlertCircle,
  Upload,
  X,
  Plus,
  Trash2,
} from "lucide-react";
import { toast } from "sonner";

export default function AdminSettingsPage() {
  const [settings, setSettings] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [formData, setFormData] = useState({});
  const [newPricing, setNewPricing] = useState({
    name: "",
    price: "",
    features: "",
  });

  useEffect(() => {
    loadSettings();
  }, []);

  async function loadSettings() {
    try {
      setLoading(true);
      const res = await fetch("/api/admin/settings");
      if (!res.ok) throw new Error("Failed to load settings");

      const data = await res.json();
      setSettings(data.settings);
      setFormData(data.settings);
    } catch (error) {
      console.error("Error loading settings:", error);
      toast.error("Failed to load settings");
    } finally {
      setLoading(false);
    }
  }

  async function handleSave() {
    try {
      setSaving(true);
      const res = await fetch("/api/admin/settings", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (!res.ok) throw new Error("Failed to save settings");

      toast.success("Settings saved successfully");
      loadSettings();
    } catch (error) {
      console.error("Error saving settings:", error);
      toast.error("Failed to save settings");
    } finally {
      setSaving(false);
    }
  }

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleFeatureChange = (feature) => {
    setFormData((prev) => ({
      ...prev,
      features: {
        ...prev.features,
        [feature]: !prev.features?.[feature],
      },
    }));
  };

  const handleLogoUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setUploading(true);
      const formDataUpload = new FormData();
      formDataUpload.append("file", file);

      const res = await fetch("/api/upload", {
        method: "POST",
        body: formDataUpload,
      });

      if (!res.ok) throw new Error("Upload failed");

      const { url } = await res.json();
      setFormData((prev) => ({
        ...prev,
        platformLogo: url,
      }));

      toast.success("Logo uploaded successfully");
    } catch (error) {
      console.error("Error uploading logo:", error);
      toast.error("Failed to upload logo");
    } finally {
      setUploading(false);
    }
  };

  const handleAddPricing = () => {
    if (!newPricing.name || !newPricing.price) {
      toast.error("Please fill in plan name and price");
      return;
    }

    const pricingPlans = formData.pricingPlans || [];
    const updatedPlans = [
      ...pricingPlans,
      {
        id: Date.now(),
        name: newPricing.name,
        price: parseFloat(newPricing.price),
        features: newPricing.features.split(",").map((f) => f.trim()),
      },
    ];

    setFormData((prev) => ({
      ...prev,
      pricingPlans: updatedPlans,
    }));

    setNewPricing({ name: "", price: "", features: "" });
    toast.success("Pricing plan added");
  };

  const handleRemovePricing = (id) => {
    setFormData((prev) => ({
      ...prev,
      pricingPlans: prev.pricingPlans?.filter((p) => p.id !== id) || [],
    }));
  };

  if (loading) {
    return (
      <ProtectedAdminRoute requiredRole="admin">
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
          <DashboardHeader />
          <div className="flex items-center justify-center py-20">
            <div className="text-center">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
              <p className="text-gray-600 dark:text-gray-400">
                Loading settings...
              </p>
            </div>
          </div>
        </div>
      </ProtectedAdminRoute>
    );
  }

  return (
    <ProtectedAdminRoute requiredRole="owner">
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />

        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Header */}
          <div className="mb-8">
            <div className="flex items-center gap-3 mb-2">
              <Settings size={32} className="text-blue-600" />
              <h1 className="text-4xl font-bold text-gray-900 dark:text-white">
                System Settings
              </h1>
            </div>
            <p className="text-gray-600 dark:text-gray-400">
              Configure platform-wide settings
            </p>
          </div>

          {/* Warning */}
          <div className="mb-8 p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-900/50 rounded-lg flex gap-3">
            <AlertCircle
              size={20}
              className="text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5"
            />
            <div>
              <p className="font-medium text-amber-800 dark:text-amber-200">
                Changes to these settings affect all restaurants on the platform
              </p>
              <p className="text-sm text-amber-700 dark:text-amber-300 mt-1">
                Only project owners can modify these settings
              </p>
            </div>
          </div>

          {/* Settings Form */}
          <div className="space-y-6">
            {/* Platform Information */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-6">
                Platform Information
              </h2>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    Platform Name
                  </label>
                  <input
                    type="text"
                    name="platformName"
                    value={formData.platformName || ""}
                    onChange={handleChange}
                    className="w-full px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    Support Email
                  </label>
                  <input
                    type="email"
                    name="platformEmail"
                    value={formData.platformEmail || ""}
                    onChange={handleChange}
                    className="w-full px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                  />
                </div>

                {/* Platform Logo */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    Platform Logo
                  </label>
                  <div className="flex items-center gap-4">
                    <div className="flex-1">
                      <label className="flex items-center justify-center px-4 py-3 border-2 border-dashed border-gray-300 dark:border-slate-600 rounded-lg cursor-pointer hover:border-blue-500 dark:hover:border-blue-500 transition">
                        <div className="flex items-center gap-2">
                          <Upload
                            size={18}
                            className="text-gray-600 dark:text-gray-400"
                          />
                          <span className="text-sm text-gray-600 dark:text-gray-400">
                            {uploading
                              ? "Uploading..."
                              : "Click to upload logo"}
                          </span>
                        </div>
                        <input
                          type="file"
                          accept="image/*"
                          onChange={handleLogoUpload}
                          disabled={uploading}
                          className="hidden"
                        />
                      </label>
                    </div>
                    {formData.platformLogo && (
                      <div className="relative w-20 h-20 rounded-lg overflow-hidden border border-gray-300 dark:border-slate-600">
                        <img
                          src={formData.platformLogo}
                          alt="Platform logo"
                          className="w-full h-full object-cover"
                        />
                        <button
                          onClick={() =>
                            setFormData((prev) => ({
                              ...prev,
                              platformLogo: "",
                            }))
                          }
                          className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded hover:bg-red-600"
                        >
                          <X size={14} />
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Custom Pricing Plans */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-6">
                Custom Pricing Plans
              </h2>

              <div className="space-y-4">
                {/* Add New Plan */}
                <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-200 dark:border-blue-900/50">
                  <p className="text-sm font-medium text-blue-900 dark:text-blue-200 mb-4">
                    Add a new pricing plan for restaurants to purchase
                  </p>
                  <div className="space-y-3">
                    <div>
                      <input
                        type="text"
                        placeholder="Plan name (e.g., Pro, Enterprise)"
                        value={newPricing.name}
                        onChange={(e) =>
                          setNewPricing((prev) => ({
                            ...prev,
                            name: e.target.value,
                          }))
                        }
                        className="w-full px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                    <div>
                      <input
                        type="number"
                        placeholder="Monthly price ($)"
                        value={newPricing.price}
                        onChange={(e) =>
                          setNewPricing((prev) => ({
                            ...prev,
                            price: e.target.value,
                          }))
                        }
                        className="w-full px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                    <div>
                      <textarea
                        placeholder="Features (comma-separated)"
                        value={newPricing.features}
                        onChange={(e) =>
                          setNewPricing((prev) => ({
                            ...prev,
                            features: e.target.value,
                          }))
                        }
                        rows={2}
                        className="w-full px-4 py-2 border border-gray-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                    <button
                      onClick={handleAddPricing}
                      className="flex items-center justify-center gap-2 w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
                    >
                      <Plus size={18} />
                      Add Plan
                    </button>
                  </div>
                </div>

                {/* Existing Plans */}
                {formData.pricingPlans && formData.pricingPlans.length > 0 ? (
                  <div className="space-y-3">
                    <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                      Active Plans ({formData.pricingPlans.length})
                    </p>
                    {formData.pricingPlans.map((plan) => (
                      <div
                        key={plan.id}
                        className="p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg border border-gray-200 dark:border-slate-600 flex items-start justify-between"
                      >
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <h3 className="text-sm font-bold text-gray-900 dark:text-white">
                              {plan.name}
                            </h3>
                            <span className="text-sm font-semibold text-green-600 dark:text-green-400">
                              ${plan.price}/mo
                            </span>
                          </div>
                          <div className="text-xs text-gray-600 dark:text-gray-400">
                            Features:{" "}
                            {plan.features?.join(", ") || "No features"}
                          </div>
                        </div>
                        <button
                          onClick={() => handleRemovePricing(plan.id)}
                          className="text-red-600 dark:text-red-400 hover:text-red-700 dark:hover:text-red-300 transition"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg text-center text-gray-600 dark:text-gray-400">
                    No pricing plans added yet
                  </div>
                )}
              </div>
            </div>

            {/* Platform Features */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-6">
                Features
              </h2>

              <div className="space-y-4">
                {[
                  {
                    id: "orders",
                    label: "Orders System",
                    description: "Allow restaurants to receive orders",
                  },
                  {
                    id: "tables",
                    label: "Table Management",
                    description: "Allow table management and QR codes",
                  },
                  {
                    id: "qrCode",
                    label: "QR Code Generation",
                    description: "Generate and scan QR codes",
                  },
                  {
                    id: "notifications",
                    label: "Notifications",
                    description: "Real-time notifications and alerts",
                  },
                ].map((feature) => (
                  <div
                    key={feature.id}
                    className="flex items-start gap-4 p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg"
                  >
                    <input
                      type="checkbox"
                      id={feature.id}
                      checked={formData.features?.[feature.id] !== false}
                      onChange={() => handleFeatureChange(feature.id)}
                      className="mt-1 w-5 h-5 text-blue-600 rounded"
                    />
                    <div className="flex-1">
                      <label
                        htmlFor={feature.id}
                        className="block text-sm font-medium text-gray-900 dark:text-white cursor-pointer"
                      >
                        {feature.label}
                      </label>
                      <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
                        {feature.description}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Platform Status */}
            <div className="bg-white dark:bg-slate-800 rounded-xl p-6 border border-gray-200 dark:border-slate-700">
              <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-6">
                Platform Status
              </h2>

              <div className="space-y-4">
                <div className="flex items-center justify-between p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg">
                  <div>
                    <p className="font-medium text-gray-900 dark:text-white">
                      Registration
                    </p>
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      Allow new restaurants to register
                    </p>
                  </div>
                  <input
                    type="checkbox"
                    name="enableRegistration"
                    checked={formData.enableRegistration !== false}
                    onChange={handleChange}
                    className="w-5 h-5 text-blue-600 rounded"
                  />
                </div>

                <div className="flex items-center justify-between p-4 bg-red-50 dark:bg-red-900/20 rounded-lg">
                  <div>
                    <p className="font-medium text-red-900 dark:text-red-200">
                      Maintenance Mode
                    </p>
                    <p className="text-sm text-red-700 dark:text-red-300">
                      Show maintenance message to all users
                    </p>
                  </div>
                  <input
                    type="checkbox"
                    name="maintenanceMode"
                    checked={formData.maintenanceMode === true}
                    onChange={handleChange}
                    className="w-5 h-5 text-red-600 rounded"
                  />
                </div>
              </div>
            </div>

            {/* Save Button */}
            <div className="flex gap-3 justify-end">
              <button
                onClick={loadSettings}
                className="flex items-center gap-2 px-6 py-2 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition text-gray-700 dark:text-gray-300"
              >
                <RefreshCw size={18} />
                Reset
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition disabled:opacity-50"
              >
                <Save size={18} />
                {saving ? "Saving..." : "Save Settings"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </ProtectedAdminRoute>
  );
}

"use client";

import ProtectedAdminRoute from "@/components/ProtectedAdminRoute";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useState, useEffect } from "react";
import {
  Search,
  RefreshCw,
  Users,
  Shield,
  Clock,
  Crown,
  CheckCircle,
  XCircle,
} from "lucide-react";
import { toast } from "sonner";

const ROLE_CONFIG = {
  owner: {
    label: "Owner",
    color:
      "bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-400",
    icon: Crown,
  },
  admin: {
    label: "Admin",
    color: "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400",
    icon: Shield,
  },
  restaurant_owner: {
    label: "Restaurant Owner",
    color:
      "bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400",
  },
  user: {
    label: "User",
    color: "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-400",
  },
};

export default function AdminUsersPage() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [updateLoading, setUpdateLoading] = useState(null);
  const [editingRole, setEditingRole] = useState(null);

  useEffect(() => {
    loadUsers();
  }, []);

  async function loadUsers() {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (searchTerm) params.append("search", searchTerm);
      if (roleFilter !== "all") params.append("role", roleFilter);

      const res = await fetch(`/api/admin/users/list?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load users");

      const data = await res.json();
      setUsers(data.users || []);
    } catch (error) {
      console.error("Error loading users:", error);
      toast.error("Failed to load users");
    } finally {
      setLoading(false);
    }
  }

  async function updateUserRole(userId, newRole) {
    try {
      setUpdateLoading(userId);
      const res = await fetch(`/api/admin/users/${userId}/role`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ role: newRole }),
      });

      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.error || "Failed to update role");
      }

      toast.success("User role updated");
      setEditingRole(null);
      loadUsers();
    } catch (error) {
      console.error("Error updating role:", error);
      toast.error(error.message || "Failed to update user role");
    } finally {
      setUpdateLoading(null);
    }
  }

  const filteredUsers = users.filter((user) => {
    if (searchTerm.toLowerCase()) {
      return (
        user.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.name?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    return true;
  });

  return (
    <ProtectedAdminRoute requiredRole="admin">
      <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
        <DashboardHeader />

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Header */}
          <div className="mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-4xl font-bold text-gray-900 dark:text-white mb-2">
                  Users Management
                </h1>
                <p className="text-gray-600 dark:text-gray-400">
                  {filteredUsers.length} user
                  {filteredUsers.length !== 1 ? "s" : ""} on the platform
                </p>
              </div>
              <button
                onClick={loadUsers}
                className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition"
              >
                <RefreshCw size={18} />
                Refresh
              </button>
            </div>

            {/* Filter Bar */}
            <div className="flex flex-col sm:flex-row gap-3">
              <div className="flex-1 relative">
                <Search
                  size={18}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"
                />
                <input
                  type="text"
                  placeholder="Search by email or name..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <select
                value={roleFilter}
                onChange={(e) => setRoleFilter(e.target.value)}
                className="px-4 py-2 border border-gray-300 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Roles</option>
                <option value="owner">Owner</option>
                <option value="admin">Admin</option>
                <option value="restaurant_owner">Restaurant Owner</option>
                <option value="user">User</option>
              </select>
            </div>
          </div>

          {/* Users Table */}
          {loading ? (
            <div className="flex items-center justify-center py-20">
              <div className="text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
                <p className="text-gray-600 dark:text-gray-400">
                  Loading users...
                </p>
              </div>
            </div>
          ) : filteredUsers.length === 0 ? (
            <div className="text-center py-20 bg-white dark:bg-slate-800 rounded-xl">
              <Users
                size={48}
                className="text-gray-300 dark:text-gray-600 mx-auto mb-4"
              />
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                No users found
              </h3>
            </div>
          ) : (
            <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm overflow-hidden border border-gray-200 dark:border-slate-700">
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50 dark:bg-slate-700/50 border-b border-gray-200 dark:border-slate-700">
                    <tr>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        User
                      </th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Role
                      </th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Restaurant
                      </th>
                      <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900 dark:text-white">
                        Joined
                      </th>
                      <th className="px-6 py-4 text-right text-sm font-semibold text-gray-900 dark:text-white">
                        Actions
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
                    {filteredUsers.map((user) => {
                      const roleConfig =
                        ROLE_CONFIG[user.role] || ROLE_CONFIG.user;
                      return (
                        <tr
                          key={user._id}
                          className="hover:bg-gray-50 dark:hover:bg-slate-700/50 transition"
                        >
                          {/* User Info */}
                          <td className="px-6 py-4">
                            <div>
                              <p className="font-semibold text-gray-900 dark:text-white">
                                {user.name || "N/A"}
                              </p>
                              <p className="text-sm text-gray-500 dark:text-gray-400">
                                {user.email}
                              </p>
                            </div>
                          </td>

                          {/* Role */}
                          <td className="px-6 py-4">
                            <span
                              className={`px-3 py-1 rounded-full text-xs font-semibold ${roleConfig.color}`}
                            >
                              {roleConfig.label}
                            </span>
                          </td>

                          {/* Restaurant */}
                          <td className="px-6 py-4">
                            <p className="text-sm text-gray-600 dark:text-gray-400">
                              {user.restaurant?.name || "-"}
                            </p>
                          </td>

                          {/* Joined Date */}
                          <td className="px-6 py-4">
                            <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                              <Clock size={14} />
                              {user.createdAt
                                ? new Date(user.createdAt).toLocaleDateString()
                                : "N/A"}
                            </div>
                          </td>

                          {/* Actions */}
                          <td className="px-6 py-4 text-right">
                            {editingRole === user._id ? (
                              <div className="flex items-center gap-2 justify-end">
                                <select
                                  defaultValue={user.role}
                                  onChange={(e) =>
                                    updateUserRole(user._id, e.target.value)
                                  }
                                  className="px-3 py-1 border border-gray-300 dark:border-slate-600 rounded text-sm bg-white dark:bg-slate-700 text-gray-900 dark:text-white"
                                >
                                  <option value="owner">Owner</option>
                                  <option value="admin">Admin</option>
                                  <option value="restaurant_owner">
                                    Restaurant Owner
                                  </option>
                                  <option value="user">User</option>
                                </select>
                                <button
                                  onClick={() => setEditingRole(null)}
                                  className="text-gray-400 hover:text-gray-600"
                                >
                                  ✕
                                </button>
                              </div>
                            ) : (
                              <button
                                onClick={() => setEditingRole(user._id)}
                                disabled={updateLoading === user._id}
                                className="text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 text-sm font-medium disabled:opacity-50"
                              >
                                {updateLoading === user._id
                                  ? "Updating..."
                                  : "Change Role"}
                              </button>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Stats */}
          {!loading && filteredUsers.length > 0 && (
            <div className="mt-8 bg-white dark:bg-slate-800 rounded-xl shadow-sm p-6 border border-gray-200 dark:border-slate-700">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                User Statistics
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {Object.entries(ROLE_CONFIG).map(([key, config]) => {
                  const count = users.filter((u) => u.role === key).length;
                  return (
                    <div
                      key={key}
                      className="p-4 bg-gray-50 dark:bg-slate-700/50 rounded-lg"
                    >
                      <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">
                        {config.label}
                      </p>
                      <p className="text-3xl font-bold text-gray-900 dark:text-white">
                        {count}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </ProtectedAdminRoute>
  );
}

"use client";

import { useState, useEffect } from "react";

import StatCard from "@/components/Dashboard/stat-card";
import { toast } from "sonner";
import { Copy, QrCode, ShoppingBag, Zap } from "lucide-react";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import { useSocket } from "@/hooks/useSocket";
import { playOrderSound, playHotActionSound } from "@/hooks/useNotifications";

export default function DashboardClient({ restaurant, user }) {
  const [showQR, setShowQR] = useState(false);
  const [stats, setStats] = useState({
    totalOrders: 0,
    totalRevenue: 0,
    customersCount: 0,
  });
  const [chartData, setChartData] = useState([]);
  const [qrScans, setQrScans] = useState(0);
  const [loading, setLoading] = useState(true);
  const [timeRange, setTimeRange] = useState("week");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [selectedDate, setSelectedDate] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  // Socket connection for real-time order notifications
  const { socket, isConnected } = useSocket(restaurant?._id);

  const getDateRange = (range) => {
    const end = new Date();
    const start = new Date();

    switch (range) {
      case "day":
        start.setDate(end.getDate() - 1);
        break;
      case "week":
        start.setDate(end.getDate() - 7);
        break;
      case "month":
        start.setDate(end.getDate() - 30);
        break;
      default:
        start.setDate(end.getDate() - 7);
    }

    return {
      start: start.toISOString().split("T")[0],
      end: end.toISOString().split("T")[0],
    };
  };

  const fetchDashboardData = async (start, end) => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (start) params.append("startDate", start);
      if (end) params.append("endDate", end);

      const queryString = params.toString();
      const [statsRes, chartRes, qrRes] = await Promise.all([
        fetch(
          `/api/me/restaurant/stats${queryString ? "?" + queryString : ""}`,
        ),
        fetch(
          `/api/me/restaurant/chart-data${queryString ? "?" + queryString : ""}`,
        ),
        fetch(
          `/api/me/restaurant/qr-scans${queryString ? "?" + queryString : ""}`,
        ),
      ]);

      if (!statsRes.ok || !chartRes.ok || !qrRes.ok) {
        throw new Error("Failed to fetch dashboard data");
      }

      const statsData = await statsRes.json();
      const chartDataArr = await chartRes.json();
      const qrData = await qrRes.json();

      setStats(statsData);
      setChartData(chartDataArr);
      setQrScans(qrData.qrScans);
    } catch (error) {
      console.error("Error fetching dashboard data:", error);
      toast.error("Failed to load dashboard data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (timeRange === "custom" && (!startDate || !endDate)) {
      return;
    }

    if (timeRange === "custom") {
      fetchDashboardData(startDate, endDate);
    } else {
      const { start, end } = getDateRange(timeRange);
      fetchDashboardData(start, end);
    }
  }, [timeRange, startDate, endDate]);

  // Listen for new orders via socket
  useEffect(() => {
    if (!socket || !isConnected) return;

    const handleNewOrder = (orderData) => {
      console.log("📦 New order received:", orderData);

      // Play notification sound
      try {
        playOrderSound();
      } catch (error) {
        console.error("Error playing order sound:", error);
      }

      // Show floating toast notification
      const itemCount = orderData.items?.length || 0;
      const amount = orderData.totalAmount || orderData.total || 0;

      toast.success(
        (t) => (
          <div className="flex items-center gap-3 w-full">
            <div className="w-10 h-10 rounded-lg bg-emerald-100 dark:bg-emerald-900/40 flex items-center justify-center flex-shrink-0">
              <ShoppingBag
                size={20}
                className="text-emerald-600 dark:text-emerald-400"
              />
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-semibold text-gray-900 dark:text-white">
                New Order!
              </p>
              <p className="text-sm text-gray-600 dark:text-gray-300">
                {itemCount} item{itemCount !== 1 ? "s" : ""} · $
                {Number(amount).toFixed(2)}
              </p>
            </div>
          </div>
        ),
        {
          duration: 5000,
          position: "top-right",
        },
      );

      // Refresh dashboard data to update stats
      const { start, end } = getDateRange(timeRange);
      fetchDashboardData(start, end);
    };

    socket.on("new-order", handleNewOrder);

    return () => {
      socket.off("new-order", handleNewOrder);
    };
  }, [socket, isConnected, timeRange, startDate, endDate]);

  // Listen for hot actions (table requests) via socket
  useEffect(() => {
    if (!socket || !isConnected) return;

    const handleHotAction = (actionData) => {
      console.log("⚡ Hot action received:", actionData);

      // Play urgent notification sound
      try {
        playHotActionSound();
      } catch (error) {
        console.error("Error playing hot action sound:", error);
      }

      // Determine hot action type
      const actionType = actionData.subType || actionData.type || "Alert";
      let message = "Table Alert!";
      let emoji = "📣";

      if (actionType.includes("bill") || actionType === "bill_request") {
        message = "Bill Request";
        emoji = "🧾";
      } else if (
        actionType.includes("waiter") ||
        actionType === "waiter_request"
      ) {
        message = "Waiter Needed";
        emoji = "🙋";
      }

      const tableNumber =
        actionData.tableNumber || actionData.table || "Unknown";

      // Show floating toast notification with urgent styling
      toast(
        (t) => (
          <div className="flex items-center gap-3 w-full">
            <div className="w-10 h-10 rounded-lg bg-orange-100 dark:bg-orange-900/40 flex items-center justify-center flex-shrink-0 animate-pulse">
              <Zap size={20} className="text-orange-600 dark:text-orange-400" />
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-bold text-gray-900 dark:text-white">
                {emoji} {message}
              </p>
              <p className="text-sm text-gray-600 dark:text-gray-300">
                Table {tableNumber}
              </p>
            </div>
          </div>
        ),
        {
          duration: 6000,
          position: "top-right",
        },
      );
    };

    socket.on("hot-action", handleHotAction);

    return () => {
      socket.off("hot-action", handleHotAction);
    };
  }, [socket, isConnected]);

  const handleTimeRangeChange = (range) => {
    setTimeRange(range);
    if (range !== "custom") {
      setStartDate("");
      setEndDate("");
    }
  };

  const handleDateClick = (date) => {
    setSelectedDate(date);
    setShowDetailModal(true);
  };

  const handleCopy = async () => {
    await navigator.clipboard.writeText(restaurant.publicUrl);
    toast.success("Link copied!");
  };

  if (!restaurant) {
    return (
      <div className="p-6 text-red-500">
        Restaurant not found. Please re-login.
      </div>
    );
  }

  const getDateRangeDisplay = () => {
    if (timeRange === "custom") {
      return `${startDate} to ${endDate}`;
    }
    const { start, end } = getDateRange(timeRange);
    return `${start} to ${end}`;
  };

  if (!restaurant) {
    return (
      <div className="p-6 text-red-500">
        Restaurant not found. Please re-login.
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <DashboardHeader restaurant={restaurant} user={user} />

      {/* Date Range Filter */}
      <div className="bg-white dark:bg-[#091f3c] rounded-xl p-6 shadow-sm">
        <div className="flex flex-col gap-4">
          <h3 className="text-lg font-semibold">Date Range</h3>
          <div className="flex flex-wrap gap-3">
            <button
              onClick={() => handleTimeRangeChange("day")}
              className={`px-4 py-2 rounded-lg font-medium transition ${
                timeRange === "day"
                  ? "bg-emerald-500 text-white"
                  : "bg-gray-100 dark:bg-[#0a1020] text-gray-700 dark:text-gray-300 hover:bg-gray-200"
              }`}
            >
              Last 24 Hours
            </button>
            <button
              onClick={() => handleTimeRangeChange("week")}
              className={`px-4 py-2 rounded-lg font-medium transition ${
                timeRange === "week"
                  ? "bg-emerald-500 text-white"
                  : "bg-gray-100 dark:bg-[#0a1020] text-gray-700 dark:text-gray-300 hover:bg-gray-200"
              }`}
            >
              Last 7 Days
            </button>
            <button
              onClick={() => handleTimeRangeChange("month")}
              className={`px-4 py-2 rounded-lg font-medium transition ${
                timeRange === "month"
                  ? "bg-emerald-500 text-white"
                  : "bg-gray-100 dark:bg-[#0a1020] text-gray-700 dark:text-gray-300 hover:bg-gray-200"
              }`}
            >
              Last 30 Days
            </button>
            <button
              onClick={() => handleTimeRangeChange("custom")}
              className={`px-4 py-2 rounded-lg font-medium transition ${
                timeRange === "custom"
                  ? "bg-emerald-500 text-white"
                  : "bg-gray-100 dark:bg-[#0a1020] text-gray-700 dark:text-gray-300 hover:bg-gray-200"
              }`}
            >
              Custom Date Range
            </button>
          </div>

          {timeRange === "custom" && (
            <div className="flex gap-4 mt-2">
              <input
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="px-4 py-2 border rounded-lg dark:bg-[#0a1020] dark:border-gray-600"
                placeholder="Start Date"
              />
              <input
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="px-4 py-2 border rounded-lg dark:bg-[#0a1020] dark:border-gray-600"
                placeholder="End Date"
              />
            </div>
          )}

          <p className="text-sm text-gray-500">
            Viewing data from:{" "}
            <span className="font-semibold">{getDateRangeDisplay()}</span>
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard
          title="Total Orders"
          value={loading ? "..." : stats.totalOrders}
          icon="🛒"
          bg="bg-[#0b1f3b]"
        />
        <StatCard
          title="Revenue"
          value={loading ? "..." : `$${stats.totalRevenue.toFixed(2)}`}
          icon="💰"
          bg="bg-emerald-500"
        />
        <StatCard
          title="Customers"
          value={loading ? "..." : stats.customersCount}
          icon="👥"
          bg="bg-[#0b1f3b]"
        />
        <StatCard
          title="QR Scans"
          value={loading ? "..." : qrScans}
          icon="📱"
          bg="bg-[#f7f3df] text-black"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-[#091f3c] rounded-xl p-6 shadow-sm h-[300px] flex flex-col">
          <h3 className="text-lg font-semibold mb-4">Orders by Date</h3>
          <p className="text-sm text-gray-500 mb-3">
            Click on a date to view details
          </p>
          {loading ? (
            <div className="flex items-center justify-center flex-1">
              Loading...
            </div>
          ) : chartData.length > 0 ? (
            <div className="flex-1 overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b">
                    <th className="text-left">Date</th>
                    <th className="text-right">Orders</th>
                    <th className="text-right">Revenue</th>
                  </tr>
                </thead>
                <tbody>
                  {chartData.map((data) => (
                    <tr
                      key={data._id}
                      onClick={() => handleDateClick(data)}
                      className="border-b hover:bg-emerald-50 dark:hover:bg-[#0a3020] cursor-pointer transition"
                    >
                      <td>{data._id}</td>
                      <td className="text-right">{data.orderCount}</td>
                      <td className="text-right">${data.revenue.toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex items-center justify-center flex-1">
              No orders found in this date range
            </div>
          )}
        </div>

        <div className="bg-white dark:bg-[#091f3c] rounded-xl p-6 shadow-sm h-[300px] flex flex-col items-center justify-center">
          <div className="text-center">
            <div className="text-5xl font-bold text-emerald-500 mb-2">
              {loading ? "..." : qrScans}
            </div>
            <p className="text-gray-500">Total QR Scans</p>
            <p className="text-sm text-gray-400 mt-2">
              Unique menu views via QR code
            </p>
          </div>
        </div>
      </div>

      {/* Date Detail Modal */}
      {showDetailModal && selectedDate && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <div className="bg-white dark:bg-[#091f3c] rounded-2xl p-6 w-full max-w-md shadow-xl space-y-4 relative">
            <button
              onClick={() => setShowDetailModal(false)}
              className="absolute top-3 right-3 text-gray-500 hover:text-gray-700"
            >
              ✕
            </button>

            <h2 className="text-xl font-semibold">
              Details for {selectedDate._id}
            </h2>

            <div className="space-y-3 border-t pt-4">
              <div className="flex justify-between items-center">
                <span className="text-gray-600 dark:text-gray-400">
                  Total Orders:
                </span>
                <span className="font-semibold text-2xl text-emerald-500">
                  {selectedDate.orderCount}
                </span>
              </div>

              <div className="flex justify-between items-center">
                <span className="text-gray-600 dark:text-gray-400">
                  Total Revenue:
                </span>
                <span className="font-semibold text-2xl">
                  ${selectedDate.revenue.toFixed(2)}
                </span>
              </div>

              <div className="flex justify-between items-center">
                <span className="text-gray-600 dark:text-gray-400">
                  Average Order:
                </span>
                <span className="font-semibold">
                  ${(selectedDate.revenue / selectedDate.orderCount).toFixed(2)}
                </span>
              </div>
            </div>

            <button
              onClick={() => setShowDetailModal(false)}
              className="w-full bg-emerald-500 text-white py-2 rounded-lg hover:bg-emerald-600 transition"
            >
              Close
            </button>
          </div>
        </div>
      )}

      {/* QR Modal */}
      {showQR && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-xl space-y-5 relative">
            <button
              onClick={() => setShowQR(false)}
              className="absolute top-3 right-3 text-gray-500"
            >
              ✕
            </button>

            <h2 className="text-xl dark:bg-[#0a1020]  font-semibold text-center">
              Restaurant QR Code
            </h2>

            <img
              src={restaurant.qrCodeBase64}
              alt="QR Code"
              className="w-48 h-48 mx-auto border rounded-xl"
            />

            <div className="text-center text-sm text-gray-600 break-all">
              {restaurant.publicUrl}
            </div>

            <div className="flex gap-3">
              <a
                href={restaurant.qrCodeBase64}
                download={`${restaurant.slug}-qr.png`}
                className="flex-1 border rounded-lg py-2 text-center dark:bg-[#0a1020]  flex items-center justify-center gap-2"
              >
                ⬇ Download
              </a>

              <button
                onClick={handleCopy}
                className="flex-1 border rounded-lg py-2 flex dark:bg-[#0a1020]  items-center justify-center gap-2"
              >
                📋 Copy Link
              </button>
            </div>

            <a
              href={restaurant.publicUrl}
              target="_blank"
              className="block text-center bg-emerald-500 text-white py-2 rounded-lg mt-2 hover:bg-emerald-600"
            >
              👁 Open Menu
            </a>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import {
  Plus,
  Trash2,
  Edit2,
  GripVertical,
  Eye,
  EyeOff,
  ChevronDown,
  ChevronRight,
  Image as ImageIcon,
  FileText,
  Copy,
  Search,
} from "lucide-react";
import DashboardHeader from "@/components/Dashboard/DashboardHeader";
import FoodFormModal from "@/components/Dashboard/FoodFormModal";
import CategoryFormModal from "@/components/Dashboard/CategoryFormModal";

export default function MenuPage() {
  const [restaurant, setRestaurant] = useState(null);
  const [categories, setCategories] = useState([]);
  const [foods, setFoods] = useState({});
  const [expandedCategories, setExpandedCategories] = useState({});
  const [openFoodForm, setOpenFoodForm] = useState(false);
  const [openCategoryForm, setOpenCategoryForm] = useState(false);
  const [editingFood, setEditingFood] = useState(null);
  const [editingCategory, setEditingCategory] = useState(null);
  const [activeCategoryId, setActiveCategoryId] = useState(null);
  const [loading, setLoading] = useState(true);
  const [menuLoading, setMenuLoading] = useState(false);
  const [error, setError] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");

  /* =============================
     Load restaurant
  ============================= */
  useEffect(() => {
    let mounted = true;

    async function loadRestaurant() {
      try {
        setLoading(true);
        setError(null);
        const res = await fetch("/api/me/restaurant", { cache: "no-store" });
        if (!res.ok) {
          const errorData = await res.json().catch(() => ({}));
          throw new Error(errorData.message || "Failed to load restaurant");
        }
        const data = await res.json();
        if (!mounted) return;

        if (!data?._id) {
          throw new Error("No restaurant found for this user");
        }

        setRestaurant(data);
      } catch (err) {
        console.error("Error loading restaurant:", err);
        if (mounted) {
          setError(err.message);
          setLoading(false);
        }
      }
    }

    loadRestaurant();
    return () => {
      mounted = false;
    };
  }, []);

  /* =============================
     Load menu data (categories & foods)
  ============================= */
  const loadMenuData = useCallback(async () => {
    if (!restaurant?._id) return;
    let mounted = true;

    try {
      setMenuLoading(true);
      setError(null);

      // Fetch categories for this restaurant
      const categoriesRes = await fetch(
        `/api/restaurants/${restaurant._id}/categories`,
        { cache: "no-store" },
      );

      if (!categoriesRes.ok) {
        const errorData = await categoriesRes.json().catch(() => ({}));
        throw new Error(errorData.message || "Failed to load categories");
      }

      const categoriesData = await categoriesRes.json();
      const categoriesList = Array.isArray(categoriesData)
        ? categoriesData
        : [];

      if (!mounted) return;

      setCategories(categoriesList);

      // Auto-expand all categories
      const expanded = {};
      categoriesList.forEach((cat) => {
        expanded[cat._id] = true;
      });
      setExpandedCategories(expanded);

      // Load foods for each category
      const foodMap = {};
      await Promise.all(
        categoriesList.map(async (category) => {
          try {
            const foodsRes = await fetch(
              `/api/restaurants/${restaurant._id}/categories/${category._id}/foods`,
              { cache: "no-store" },
            );
            if (foodsRes.ok) {
              const foodsData = await foodsRes.json();
              foodMap[category._id] = Array.isArray(foodsData) ? foodsData : [];
            } else {
              console.warn(`Failed to load foods for category ${category._id}`);
              foodMap[category._id] = [];
            }
          } catch (err) {
            console.error(
              `Error loading foods for category ${category._id}:`,
              err,
            );
            foodMap[category._id] = [];
          }
        }),
      );

      if (!mounted) return;
      setFoods(foodMap);
    } catch (err) {
      console.error("Error loading menu data:", err);
      if (mounted) {
        setError(err.message);
      }
    } finally {
      if (mounted) {
        setMenuLoading(false);
        setLoading(false);
      }
    }
  }, [restaurant]);

  useEffect(() => {
    if (restaurant?._id) {
      loadMenuData();
    }
  }, [restaurant, loadMenuData]);

  /* =============================
     Actions
  ============================= */
  function toggleCategory(categoryId) {
    setExpandedCategories((prev) => ({
      ...prev,
      [categoryId]: !prev[categoryId],
    }));
  }

  function openEditCategory(category) {
    setEditingCategory(category);
    setOpenCategoryForm(true);
  }

  async function deleteCategory(categoryId) {
    if (!categoryId) {
      console.error("Cannot delete category: categoryId is missing");
      alert("Error: Cannot delete this category. Please try again.");
      return;
    }
    const foodCount = (foods[categoryId] || []).length;
    if (
      !confirm(
        foodCount > 0
          ? `Delete category with ${foodCount} items? This will permanently delete all items in this category.`
          : "Delete category?",
      )
    )
      return;

    // Store original state in case we need to revert
    const originalCategories = categories;
    const originalFoods = foods;

    try {
      const res = await fetch(
        `/api/restaurants/${restaurant._id}/categories/${categoryId}`,
        {
          method: "DELETE",
          headers: {
            "Cache-Control": "no-cache, no-store, must-revalidate",
            Pragma: "no-cache",
            Expires: "0",
          },
        },
      );

      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.message || "Failed to delete category");
      }

      const result = await res.json();
      console.log(
        `[Frontend] Category deleted successfully: ${categoryId}`,
        result,
      );
      console.log(`[Frontend] Foods deleted: ${result.foodsDeleted || 0}`);

      // Remove from state immediately for UI feedback
      setCategories((prev) => prev.filter((c) => c._id !== categoryId));
      setFoods((prev) => {
        const newFoods = { ...prev };
        delete newFoods[categoryId];
        return newFoods;
      });

      // Wait a bit then reload all categories and foods to verify deletion
      await new Promise((resolve) => setTimeout(resolve, 500));

      try {
        const timestamp = Date.now();
        const categoriesRes = await fetch(
          `/api/restaurants/${restaurant._id}/categories?t=${timestamp}`,
          {
            method: "GET",
            cache: "no-store",
            headers: {
              "Cache-Control": "no-cache, no-store, must-revalidate",
              Pragma: "no-cache",
              Expires: "0",
            },
          },
        );
        if (categoriesRes.ok) {
          const categoriesData = await categoriesRes.json();
          const categoriesList = Array.isArray(categoriesData)
            ? categoriesData
            : [];

          // Verify category is actually deleted
          const categoryStillExists = categoriesList.some(
            (c) => c._id === categoryId,
          );
          if (categoryStillExists) {
            console.error(
              `[Frontend] ❌ DELETION FAILED - Category ${categoryId} still exists!`,
            );
            setCategories(originalCategories);
            setFoods(originalFoods);
            alert(
              "Error: Failed to permanently delete the category. Please try again.",
            );
            return;
          }

          setCategories(categoriesList);
          console.log(
            `✅ [Frontend] Category deletion VERIFIED - Remaining: ${categoriesList.length} categories`,
          );

          // Also reload all foods to verify foods were deleted
          const foodMap = {};
          await Promise.all(
            categoriesList.map(async (category) => {
              try {
                const foodsRes = await fetch(
                  `/api/restaurants/${restaurant._id}/categories/${category._id}/foods?t=${timestamp}`,
                  {
                    cache: "no-store",
                    headers: {
                      "Cache-Control": "no-cache, no-store, must-revalidate",
                    },
                  },
                );
                if (foodsRes.ok) {
                  const foodsData = await foodsRes.json();
                  foodMap[category._id] = Array.isArray(foodsData)
                    ? foodsData
                    : [];
                } else {
                  foodMap[category._id] = [];
                }
              } catch (err) {
                console.warn(
                  `Failed to load foods for category ${category._id}`,
                );
                foodMap[category._id] = [];
              }
            }),
          );
          setFoods(foodMap);
        }
      } catch (reloadErr) {
        console.error(
          "[Frontend] Error reloading categories after delete:",
          reloadErr,
        );
      }
    } catch (err) {
      console.error("Delete category error:", err);
      alert(`Error: ${err.message}`);
    }
  }

  async function duplicateCategory(category) {
    if (!category || !category._id) {
      console.error(
        "Cannot duplicate category: category or categoryId is missing",
      );
      alert("Error: Cannot duplicate this category. Please try again.");
      return;
    }
    try {
      const newCategoryRes = await fetch(
        `/api/restaurants/${restaurant._id}/categories`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: `${category.name} (Copy)`,
            description: category.description,
          }),
        },
      );
      if (!newCategoryRes.ok) {
        const errorData = await newCategoryRes.json().catch(() => ({}));
        throw new Error(errorData.message || "Failed to duplicate category");
      }
      const newCategory = await newCategoryRes.json();
      if (!newCategory || !newCategory._id) {
        throw new Error("Duplicated category was not created properly");
      }

      const categoryFoods = foods[category._id] || [];
      const newFoods = [];
      for (const food of categoryFoods) {
        const foodRes = await fetch(
          `/api/restaurants/${restaurant._id}/categories/${newCategory._id}/foods`,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              name: food.name,
              description: food.description,
              price: food.price,
              image: food.image,
              isAvailable: food.isAvailable,
            }),
          },
        );
        if (foodRes.ok) {
          const newFood = await foodRes.json();
          if (newFood && newFood._id) {
            newFoods.push(newFood);
          }
        }
      }
      console.log(
        `Category duplicated: ${category._id} -> ${newCategory._id} with ${newFoods.length} items`,
      );
      setCategories((prev) => [...prev, newCategory]);
      setFoods((prev) => ({ ...prev, [newCategory._id]: newFoods }));
    } catch (err) {
      console.error("Duplicate category error:", err);
      alert(`Error: ${err.message}`);
    }
  }

  function openCreateFood(categoryId) {
    console.log("openCreateFood called with categoryId:", categoryId);
    // FIX: Validate categoryId before proceeding
    if (!categoryId) {
      console.error("Cannot create food: categoryId is undefined");
      alert("Error: Category ID is missing. Please try again.");
      return;
    }
    setActiveCategoryId(categoryId);
    setEditingFood(null);
    setOpenFoodForm(true);
  }

  function openEditFood(food, categoryId) {
    // FIX: Validate categoryId before proceeding
    if (!categoryId) {
      console.error("Cannot edit food: categoryId is undefined");
      alert("Error: Category ID is missing. Please try again.");
      return;
    }
    setEditingFood({ ...food, categoryId });
    setActiveCategoryId(categoryId);
    setOpenFoodForm(true);
  }

  async function toggleFoodAvailability(food, categoryId) {
    if (!food || !food._id || !categoryId) {
      console.error(
        "Cannot toggle availability: food or categoryId is missing",
      );
      alert("Error: Cannot update availability. Please try again.");
      return;
    }
    try {
      const newStatus = !food.isAvailable;
      const res = await fetch(
        `/api/restaurants/${restaurant._id}/foods/${food._id}`,
        {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ isAvailable: newStatus }),
        },
      );
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.message || "Failed to update availability");
      }
      console.log(`Food availability toggled: ${food._id} -> ${newStatus}`);
      setFoods((prev) => ({
        ...prev,
        [categoryId]: (prev[categoryId] || []).map((f) =>
          f._id === food._id ? { ...f, isAvailable: newStatus } : f,
        ),
      }));
    } catch (err) {
      console.error("Availability toggle error:", err);
      alert(`Error: ${err.message}`);
    }
  }

  async function deleteFood(foodId, categoryId) {
    if (!confirm("Delete this item?")) return;
    if (!foodId || !categoryId) {
      console.error("Cannot delete food: foodId or categoryId is missing");
      alert("Error: Cannot delete this item. Please try again.");
      return;
    }

    // Store original foods in case we need to revert
    const originalFoods = foods[categoryId] || [];

    try {
      console.log(`[Frontend] Deleting food: ${foodId}`);

      const res = await fetch(
        `/api/restaurants/${restaurant._id}/foods/${foodId}`,
        {
          method: "DELETE",
          headers: {
            "Cache-Control": "no-cache, no-store, must-revalidate",
            Pragma: "no-cache",
            Expires: "0",
          },
        },
      );

      const result = await res.json();
      console.log(`[Frontend] Delete API response:`, result);

      if (!res.ok) {
        throw new Error(result.error || "Failed to delete food");
      }

      console.log(`[Frontend] Food deletion confirmed by API: ${foodId}`);

      // Update state immediately for UI feedback
      setFoods((prev) => ({
        ...prev,
        [categoryId]: (prev[categoryId] || []).filter((f) => f._id !== foodId),
      }));

      // Wait a bit then reload foods for verification (with cache busting)
      await new Promise((resolve) => setTimeout(resolve, 500));

      try {
        const timestamp = Date.now();
        const foodsRes = await fetch(
          `/api/restaurants/${restaurant._id}/categories/${categoryId}/foods?t=${timestamp}`,
          {
            method: "GET",
            cache: "no-store",
            headers: {
              "Cache-Control": "no-cache, no-store, must-revalidate",
              Pragma: "no-cache",
              Expires: "0",
            },
          },
        );

        if (foodsRes.ok) {
          const foodsData = await foodsRes.json();
          const updatedFoods = Array.isArray(foodsData) ? foodsData : [];

          // Check if item was actually deleted
          const itemStillExists = updatedFoods.some((f) => f._id === foodId);

          if (itemStillExists) {
            console.error(
              `[Frontend] ❌ DELETION FAILED - Item ${foodId} still exists in database!`,
            );
            // Revert the UI change
            setFoods((prev) => ({
              ...prev,
              [categoryId]: originalFoods,
            }));
            alert(
              "Error: Failed to permanently delete the item. It still exists in the database. Please try again.",
            );
            return;
          }

          setFoods((prev) => ({
            ...prev,
            [categoryId]: updatedFoods,
          }));
          console.log(
            `✅ [Frontend] Deletion VERIFIED - Item removed from database. Remaining: ${updatedFoods.length}`,
          );
        } else {
          console.warn("[Frontend] Could not fetch foods for verification");
        }
      } catch (reloadErr) {
        console.error(
          "[Frontend] Error reloading foods for verification:",
          reloadErr,
        );
      }
    } catch (err) {
      console.error("[Frontend] Delete error:", err);
      alert(`Error: ${err.message}`);
    }
  }

  async function duplicateFood(food, categoryId) {
    if (!food || !food._id || !categoryId) {
      console.error("Cannot duplicate food: food or categoryId is missing");
      alert("Error: Cannot duplicate this item. Please try again.");
      return;
    }
    try {
      const res = await fetch(
        `/api/restaurants/${restaurant._id}/categories/${categoryId}/foods`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: `${food.name} (Copy)`,
            description: food.description,
            price: food.price,
            image: food.image,
            isAvailable: food.isAvailable,
          }),
        },
      );
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.message || "Failed to duplicate food");
      }
      const newFood = await res.json();
      if (!newFood || !newFood._id) {
        throw new Error("Duplicated food item was not created properly");
      }
      console.log(`Food duplicated: ${food._id} -> ${newFood._id}`);
      setFoods((prev) => ({
        ...prev,
        [categoryId]: [newFood, ...(prev[categoryId] || [])],
      }));
    } catch (err) {
      console.error("Duplicate error:", err);
      alert(`Error: ${err.message}`);
    }
  }

  function onFoodSaved(savedFood, mode) {
    // FIX: Always use activeCategoryId for the category
    const cid = activeCategoryId;

    if (!cid) {
      console.error("Cannot save food: categoryId is undefined");
      alert("Error: Category ID is missing. Please try again.");
      return;
    }

    if (!savedFood || !savedFood._id) {
      console.error(
        "Cannot save food: food object or _id is missing",
        savedFood,
      );
      alert("Error: Food was not saved properly. Please try again.");
      return;
    }

    console.log(
      `Saving food in mode: ${mode}, foodId: ${savedFood._id}, categoryId: ${cid}`,
    );

    setFoods((prev) => {
      const list = prev[cid] || [];
      const updatedList =
        mode === "create"
          ? [savedFood, ...list]
          : list.map((f) => (f._id === savedFood._id ? savedFood : f));

      console.log(
        `Updated foods list for category ${cid}:`,
        updatedList.length,
        "items",
      );
      return {
        ...prev,
        [cid]: updatedList,
      };
    });
    setOpenFoodForm(false);
    setEditingFood(null);
    setActiveCategoryId(null);
  }

  function onCategoryCreated(newCategory) {
    if (!newCategory || !newCategory._id) {
      console.error(
        "Cannot create category: category object or _id is missing",
        newCategory,
      );
      alert("Error: Category was not created properly. Please try again.");
      return;
    }

    console.log(
      `Category ${editingCategory ? "updated" : "created"}: ${newCategory._id}`,
    );

    if (editingCategory) {
      setCategories((prev) =>
        prev.map((c) => (c._id === newCategory._id ? newCategory : c)),
      );
    } else {
      setCategories((prev) => [...prev, newCategory]);
      setFoods((prev) => ({ ...prev, [newCategory._id]: [] }));
    }
    setOpenCategoryForm(false);
    setEditingCategory(null);
  }

  /* =============================
     Stats & Filter
  ============================= */
  const filteredCategories = categories.filter((cat) => {
    if (!searchQuery) return true;
    const query = searchQuery.toLowerCase();
    if (cat.name.toLowerCase().includes(query)) return true;
    const categoryFoods = foods[cat._id] || [];
    return categoryFoods.some((food) =>
      food.name.toLowerCase().includes(query),
    );
  });

  const totalItems = Object.values(foods).reduce(
    (sum, items) => sum + items.length,
    0,
  );
  const availableItems = Object.values(foods).reduce(
    (sum, items) => sum + items.filter((f) => f.isAvailable).length,
    0,
  );

  /* =============================
     Render
  ============================= */
  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50 dark:bg-slate-950">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-500 dark:text-slate-400">Loading menu...</p>
        </div>
      </div>
    );
  }

  if (error && !restaurant) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50 dark:bg-slate-950">
        <div className="text-center max-w-md">
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/40 rounded-lg p-6">
            <h3 className="text-lg font-semibold text-red-800 dark:text-red-400 mb-2">
              Error Loading Restaurant
            </h3>
            <p className="text-red-600 dark:text-red-300 mb-4">{error}</p>
            <button
              onClick={() => window.location.reload()}
              className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition"
            >
              Retry
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
      <DashboardHeader />
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        {/* Page Header */}
        <div className="mb-6">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h1 className="text-3xl font-bold text-gray-900 dark:text-stone-100">
                Menus
              </h1>
              <p className="text-sm text-gray-500 dark:text-slate-400 mt-1">
                {restaurant?.name}
              </p>
            </div>
            <button
              onClick={() => {
                setEditingCategory(null);
                setOpenCategoryForm(true);
              }}
              className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-lg hover:bg-blue-700 transition font-medium shadow-sm"
            >
              <Plus size={20} />
              New Category
            </button>
          </div>

          {/* Stats */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 p-4">
              <div className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                Categories
              </div>
              <div className="text-2xl font-bold text-gray-900 dark:text-stone-100">
                {categories.length}
              </div>
            </div>
            <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 p-4">
              <div className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                Total Items
              </div>
              <div className="text-2xl font-bold text-gray-900 dark:text-stone-100">
                {totalItems}
              </div>
            </div>
            <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 p-4">
              <div className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                Available
              </div>
              <div className="text-2xl font-bold text-green-600 dark:text-green-400">
                {availableItems}
              </div>
            </div>
            <div className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 p-4">
              <div className="text-sm text-gray-500 dark:text-slate-400 mb-1">
                Hidden
              </div>
              <div className="text-2xl font-bold text-gray-400 dark:text-slate-500">
                {totalItems - availableItems}
              </div>
            </div>
          </div>

          {/* Search */}
          <div className="relative">
            <Search
              className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 dark:text-slate-500"
              size={20}
            />
            <input
              type="text"
              placeholder="Search categories or items..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-3 border border-gray-300 dark:border-slate-700 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white dark:bg-slate-800 text-gray-900 dark:text-slate-100 placeholder-gray-500 dark:placeholder-slate-400"
            />
          </div>
        </div>

        {/* Error Display */}
        {error && (
          <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-900/40 rounded-lg p-4 mb-6">
            <p className="text-yellow-800 dark:text-yellow-300">{error}</p>
          </div>
        )}

        {/* Menu List */}
        {menuLoading ? (
          <div className="flex items-center justify-center py-12">
            <div className="text-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-2"></div>
              <p className="text-gray-500 dark:text-slate-400 text-sm">
                Loading categories...
              </p>
            </div>
          </div>
        ) : filteredCategories.length === 0 ? (
          <div className="bg-white dark:bg-slate-800 rounded-lg border-2 border-dashed border-gray-300 dark:border-slate-700 p-12 text-center">
            <FileText className="mx-auto h-12 w-12 text-gray-400 dark:text-slate-500 mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 dark:text-stone-100 mb-2">
              {searchQuery ? "No results found" : "No categories yet"}
            </h3>
            <p className="text-gray-500 dark:text-slate-400 mb-6">
              {searchQuery
                ? "Try a different search"
                : "Create your first category to start building your menu"}
            </p>
            {!searchQuery && (
              <button
                onClick={() => setOpenCategoryForm(true)}
                className="bg-blue-600 text-white px-6 py-2.5 rounded-lg hover:bg-blue-700 transition"
              >
                Create Category
              </button>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {filteredCategories.map((category) => {
              const categoryFoods = foods[category._id] || [];
              const isExpanded = expandedCategories[category._id];
              return (
                <div
                  key={category._id}
                  className="bg-white dark:bg-slate-800 rounded-lg border border-gray-200 dark:border-slate-700 shadow-sm"
                >
                  {/* Category Header */}
                  <div className="bg-gradient-to-r from-gray-50 dark:from-slate-700 to-white dark:to-slate-800 border-b border-gray-200 dark:border-slate-700">
                    <div className="flex items-center justify-between p-4">
                      <div className="flex items-center gap-3 flex-1">
                        <button
                          onClick={() => toggleCategory(category._id)}
                          className="text-gray-400 dark:text-slate-500 hover:text-gray-600 dark:hover:text-slate-400 transition"
                        >
                          {isExpanded ? (
                            <ChevronDown size={20} />
                          ) : (
                            <ChevronRight size={20} />
                          )}
                        </button>
                        <GripVertical
                          size={20}
                          className="text-gray-300 dark:text-slate-500 cursor-move"
                        />
                        <div className="flex-1">
                          <h3 className="text-lg font-semibold text-gray-900 dark:text-stone-100">
                            {category.name}
                          </h3>
                          {category.description && (
                            <p className="text-sm text-gray-500 dark:text-slate-400 mt-0.5">
                              {category.description}
                            </p>
                          )}
                        </div>
                        <span className="bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-400 px-3 py-1 rounded-full text-sm font-medium">
                          {categoryFoods.length}
                        </span>
                      </div>
                      <div className="flex items-center gap-1 ml-4">
                        <button
                          onClick={() => openCreateFood(category._id)}
                          className="flex items-center gap-1.5 text-sm bg-blue-600 text-white px-3 py-2 rounded hover:bg-blue-700 transition"
                        >
                          <Plus size={16} /> Add Item
                        </button>
                        <button
                          onClick={() => openEditCategory(category)}
                          className="p-2 text-gray-600 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                          title="Edit"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button
                          onClick={() => duplicateCategory(category)}
                          className="p-2 text-gray-600 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                          title="Duplicate"
                        >
                          <Copy size={16} />
                        </button>
                        <button
                          onClick={() => deleteCategory(category._id)}
                          className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded transition"
                          title="Delete"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Items */}
                  {isExpanded && (
                    <div className="divide-y divide-gray-100 dark:divide-slate-700">
                      {categoryFoods.length === 0 ? (
                        <div className="p-8 text-center">
                          <p className="text-gray-400 dark:text-slate-500 mb-3">
                            No items yet
                          </p>
                          <button
                            onClick={() => openCreateFood(category._id)}
                            className="text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 text-sm font-medium"
                          >
                            + Add first item
                          </button>
                        </div>
                      ) : (
                        categoryFoods.map((food) => (
                          <div
                            key={food._id}
                            className="flex items-center gap-4 p-4 hover:bg-gray-50 dark:hover:bg-slate-700/40 transition group"
                          >
                            <GripVertical
                              size={18}
                              className="text-gray-300 dark:text-slate-500 cursor-move opacity-0 group-hover:opacity-100 transition"
                            />
                            <div className="w-14 h-14 bg-gray-100 dark:bg-slate-700 rounded-lg overflow-hidden flex-shrink-0">
                              {food.image ? (
                                <img
                                  src={food.image}
                                  alt={food.name}
                                  className="w-full h-full object-cover"
                                />
                              ) : (
                                <div className="w-full h-full flex items-center justify-center">
                                  <ImageIcon
                                    size={20}
                                    className="text-gray-400 dark:text-slate-500"
                                  />
                                </div>
                              )}
                            </div>
                            <div className="flex-1 min-w-0">
                              <h4 className="font-medium text-gray-900 dark:text-stone-100 truncate">
                                {food.name}
                              </h4>
                              <p className="text-sm text-gray-500 dark:text-slate-400 truncate">
                                {food.description || "No description"}
                              </p>
                            </div>
                            <div className="text-right flex-shrink-0 w-20">
                              <div className="font-semibold text-gray-900 dark:text-stone-100">
                                {food.price != null
                                  ? `$${Number(food.price).toFixed(2)}`
                                  : "—"}
                              </div>
                            </div>
                            <div className="flex items-center gap-1 flex-shrink-0 opacity-0 group-hover:opacity-100 transition">
                              <button
                                onClick={() =>
                                  toggleFoodAvailability(food, category._id)
                                }
                                className={`p-2 rounded transition ${food.isAvailable ? "text-green-600 dark:text-green-400 hover:bg-green-50 dark:hover:bg-green-900/20" : "text-gray-400 dark:text-slate-500 hover:bg-gray-100 dark:hover:bg-slate-700"}`}
                                title={food.isAvailable ? "Hide" : "Show"}
                              >
                                {food.isAvailable ? (
                                  <Eye size={18} />
                                ) : (
                                  <EyeOff size={18} />
                                )}
                              </button>
                              <button
                                onClick={() => openEditFood(food, category._id)}
                                className="p-2 text-gray-600 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                                title="Edit"
                              >
                                <Edit2 size={18} />
                              </button>
                              <button
                                onClick={() =>
                                  duplicateFood(food, category._id)
                                }
                                className="p-2 text-gray-600 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-700 rounded transition"
                                title="Duplicate"
                              >
                                <Copy size={18} />
                              </button>
                              <button
                                onClick={() =>
                                  deleteFood(food._id, category._id)
                                }
                                className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded transition"
                                title="Delete"
                              >
                                <Trash2 size={18} />
                              </button>
                            </div>
                          </div>
                        ))
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Modals */}
      {openFoodForm && (
        <FoodFormModal
          restaurantId={restaurant._id}
          categoryId={activeCategoryId}
          initialData={editingFood}
          onClose={() => {
            setOpenFoodForm(false);
            setEditingFood(null);
            setActiveCategoryId(null);
          }}
          onSaved={onFoodSaved}
        />
      )}
      {openCategoryForm && (
        <CategoryFormModal
          restaurantId={restaurant._id}
          initialData={editingCategory}
          onClose={() => {
            setOpenCategoryForm(false);
            setEditingCategory(null);
          }}
          onCreated={onCategoryCreated}
        />
      )}
    </div>
  );
}

