    font-size: 11px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: #ccc;
    white-space: nowrap;
  }

  /* ── SUBMIT ── */
  .rp-submit {
    width: 100%;
    height: 50px;
    background: linear-gradient(135deg, #ff6b35 0%, #ff8c42 100%);
    color: white;
    border: none;
    border-radius: 12px;
    font-family: 'Bricolage Grotesque', sans-serif;
    font-size: 16px;
    font-weight: 700;
    letter-spacing: -0.2px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    transition: transform 0.2s, box-shadow 0.2s, opacity 0.2s;
    box-shadow: 0 4px 20px rgba(255,107,53,0.35);
    margin-bottom: 20px;
  }

  .rp-submit:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 8px 28px rgba(255,107,53,0.45);
  }

  .rp-submit:active:not(:disabled) {
    transform: translateY(0);
  }

  .rp-submit:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }

  /* ── TRUST BAR ── */
  .rp-trust {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 20px;
    padding: 14px 20px;
    background: #fafaf9;
    border-radius: 10px;
    border: 1px solid #f0f0ee;
    margin-top: 16px;
  }

  .rp-trust-item {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    color: #666;
    font-weight: 500;
  }

  .rp-trust-icon { color: #ff6b35; }

  .rp-login-hint {
    text-align: center;
    font-size: 13px;
    color: #888;
  }

  .rp-login-hint a {
    color: #ff6b35;
    font-weight: 600;
    text-decoration: none;
  }

  .rp-login-hint a:hover { text-decoration: underline; }

  /* ── FOOTER ── */
  .rp-footer {
    position: relative;
    z-index: 1;
    text-align: center;
    padding: 24px;
    font-size: 12px;
    color: #bbb;
    display: flex;
    justify-content: center;
    gap: 24px;
  }

  /* ── FLOATING BADGE ── */
  .rp-float-badge {
    position: fixed;
    bottom: 24px;
    right: 24px;
    background: white;
    border-radius: 14px;
    padding: 14px 18px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.12);
    border: 1px solid rgba(0,0,0,0.06);
    display: flex;
    align-items: center;
    gap: 10px;
    z-index: 50;
    animation: badgeIn 0.8s 1s cubic-bezier(0.34,1.3,0.64,1) both;
  }

  @keyframes badgeIn {
    from { opacity: 0; transform: translateY(20px) scale(0.9); }
    to   { opacity: 1; transform: translateY(0) scale(1); }
  }

  .rp-float-avatar {
    display: flex;
    flex-direction: row-reverse;
  }

  .rp-float-avatar span {
    width: 28px; height: 28px;
    border-radius: 50%;
    border: 2px solid white;
    display: flex; align-items: center; justify-content: center;
    font-size: 13px;
    margin-left: -8px;
  }

  .rp-float-avatar span:last-child { margin-left: 0; }

  .rp-float-text { font-size: 12px; line-height: 1.4; }
  .rp-float-text strong { font-weight: 700; font-size: 13px; display: block; color: #1a1a1a; }
  .rp-float-text span { color: #888; }

  /* ── RESPONSIVE ── */
  @media (max-width: 1200px) {
    .rp-main { grid-template-columns: 1fr 540px 1fr; }
    .rp-col-left, .rp-col-right { padding-left: 24px; padding-right: 24px; }
  }

  @media (max-width: 960px) {
    .rp-main { grid-template-columns: 1fr; padding: 32px 16px 48px; }
    .rp-col-left, .rp-col-right { display: none; }
  }

  @media (max-width: 520px) {
    .rp-header { padding: 28px 24px 24px; }
    .rp-body { padding: 24px; }
    .rp-grid { grid-template-columns: 1fr; }
    .rp-field.full { grid-column: 1; }
    .rp-title { font-size: 22px; }
    .rp-float-badge { display: none; }
  }

  /* Input field animation on load */
  .rp-field {
    animation: fieldIn 0.5s ease both;
  }
  .rp-field:nth-child(1)  { animation-delay: 0.05s; }
  .rp-field:nth-child(2)  { animation-delay: 0.10s; }
  .rp-field:nth-child(3)  { animation-delay: 0.15s; }
  .rp-field:nth-child(4)  { animation-delay: 0.20s; }
  .rp-field:nth-child(5)  { animation-delay: 0.25s; }
  .rp-field:nth-child(6)  { animation-delay: 0.30s; }
  .rp-field:nth-child(7)  { animation-delay: 0.35s; }
  .rp-field:nth-child(8)  { animation-delay: 0.40s; }
  .rp-field:nth-child(9)  { animation-delay: 0.45s; }
  .rp-field:nth-child(10) { animation-delay: 0.50s; }

  @keyframes fieldIn {
    from { opacity: 0; transform: translateY(10px); }
    to   { opacity: 1; transform: translateY(0); }
  }
`;

/* ── Field component ─────────────────────────────────────── */
function Field({ label, hint, icon: Icon, children, full }) {
  return (
    <div className={`rp-field${full ? " full" : ""}`}>
      <label className="rp-label">{label}</label>
      <div className="rp-input-wrap">
        {Icon && <Icon size={14} className="rp-input-icon" />}
        {children}
      </div>
      {hint && <p className="rp-hint">{hint}</p>}
    </div>
  );
}

/* ── Main Component ──────────────────────────────────────── */
export default function RegisterPage() {
  const [loading, setLoading] = useState(false);
  const [category, setCategory] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const router = useRouter();
  const { settings } = usePlatformSettings();

  async function handleSubmit(e) {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());

    if (data.password !== data.confirmPassword) {
      toast.error("Passwords do not match");
      setLoading(false);
      return;
    }

    const res = await fetch("/api/auth/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    });

    const result = await res.json();

    if (!res.ok) {
      toast.error(result.message || "Registration failed");
      setLoading(false);
      return;
    }

    await signIn("credentials", {
      email: data.email,
      password: data.password,
      redirect: false,
    });

    toast.success("Welcome! Your restaurant account is ready 🎉");
    router.push("/dashboard");
  }

  return (
    <>
      <style>{css}</style>
      <div className="rp-root">
        {/* ── NAV ── */}
        <nav className="rp-nav">
          <Link href="/" className="rp-logo">
            <div className="rp-logo-icon">
              {settings?.platformLogo ? (
                <img
                  src={settings.platformLogo}
                  alt="Logo"
                  className="w-full h-full rounded-lg object-cover"
                />
              ) : (
                <ChefHat size={18} color="white" />
              )}
            </div>
            <span className="rp-logo-text">
              {settings?.platformName || "RestaurantOS"}
            </span>
          </Link>
          <span className="rp-nav-hint">
            Already have an account? <Link href="/login">Sign in →</Link>
          </span>
        </nav>

        {/* ── MAIN ── */}
        <main className="rp-main">
          {/* Left sidebar — social proof */}
          <div className="rp-col-left">
            <div className="rp-side-card" style={{ animationDelay: "0.3s" }}>
              <div className="rp-side-icon" style={{ background: "#fff3ed" }}>
                <Store size={16} color="#ff6b35" />
              </div>
              <div className="rp-side-stat" style={{ color: "#ff6b35" }}>
                12k+
              </div>
              <div className="rp-side-label">Restaurants on platform</div>
            </div>
            <div className="rp-side-card" style={{ animationDelay: "0.45s" }}>
              <div className="rp-side-icon" style={{ background: "#f0fdf4" }}>
                <CheckCircle2 size={16} color="#34a853" />
              </div>
              <div className="rp-side-stat" style={{ color: "#34a853" }}>
                5M+
              </div>
              <div className="rp-side-label">Orders processed monthly</div>
            </div>
            <div className="rp-side-card" style={{ animationDelay: "0.6s" }}>
              <div style={{ display: "flex", gap: 3, marginBottom: 10 }}>
                {[...Array(5)].map((_, i) => (
                  <span key={i} style={{ color: "#ffa500", fontSize: 15 }}>
                    ★
                  </span>
                ))}
              </div>
              <div
                className="rp-side-stat"
                style={{ color: "#1a1a1a", fontSize: 24 }}
              >
                &quot;Changed how we operate&quot;
              </div>
              <div className="rp-side-label" style={{ marginTop: 6 }}>
                — Marco R., Bella Italia
              </div>
            </div>
          </div>

          {/* ── CENTER: FORM CARD ── */}
          <div className="rp-col-center">
            <div className="rp-card">
              {/* Header */}
              <div className="rp-header">
                <div className="rp-header-inner">
                  <div className="rp-header-top">
                    <div className="rp-header-icon">
                      <Store size={24} />
                    </div>
                    <div>
                      <span className="rp-eyebrow">
                        New Account · Free Trial
                      </span>
                      <h1 className="rp-title">
                        Register Your
                        <br />
                        <em>Restaurant</em>
                      </h1>
                    </div>
                  </div>
                  <p className="rp-subtitle">
                    Set up your restaurant and start managing orders, tables,
                    and revenue — all in one place. Ready in under 5 minutes.
                  </p>
                  <div className="rp-progress">
                    <div className="rp-progress-dot active" />
                    <div className="rp-progress-dot inactive" />
                    <div className="rp-progress-dot inactive" />
                  </div>
                </div>
              </div>

              {/* Form body */}
              <div className="rp-body">
                <form onSubmit={handleSubmit}>
                  {/* ── SECTION 1: Restaurant Info ── */}
                  <div className="rp-section">
                    <div className="rp-section-header">
                      <div
                        className="rp-section-icon"
                        style={{ background: "#fff3ed" }}
                      >
                        <Store size={15} color="#ff6b35" />
                      </div>
                      <div className="rp-section-text">
                        <span className="rp-section-title">
                          Restaurant Information
                        </span>
                        <span className="rp-section-num">Section 01 of 02</span>
                      </div>
                    </div>

                    <div className="rp-grid">
                      <Field
                        label="Restaurant Name"
                        icon={Store}
                        hint="The name your customers will see"
                      >
                        <Input
                          name="restaurantName"
                          placeholder="Burger Palace"
                          required
                          autoFocus
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Cuisine Type"
                        hint="Helps us customize your dashboard"
                      >
                        <div className="rp-select" style={{ width: "100%" }}>
                          <Select value={category} onValueChange={setCategory}>
                            <SelectTrigger
                              className="rp-input"
                              style={{
                                paddingLeft: 14,
                                height: 42,
                                border: "1.5px solid #e8e8e8",
                                borderRadius: 10,
                                background: "#fafaf9",
                                fontSize: 13.5,
                              }}
                            >
                              <SelectValue placeholder="Select cuisine…" />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="fast-food">
                                🍔 Fast Food
                              </SelectItem>
                              <SelectItem value="cafe">☕ Café</SelectItem>
                              <SelectItem value="fine-dining">
                                🍷 Fine Dining
                              </SelectItem>
                              <SelectItem value="desserts">
                                🍰 Desserts
                              </SelectItem>
                              <SelectItem value="pizza">🍕 Pizza</SelectItem>
                              <SelectItem value="asian">🍜 Asian</SelectItem>
                              <SelectItem value="other">🍽️ Other</SelectItem>
                            </SelectContent>
                          </Select>
                          <input
                            type="hidden"
                            name="category"
                            value={category}
                          />
                        </div>
                      </Field>

                      <Field
                        label="Mall / Location"
                        icon={MapPin}
                        hint="Where your restaurant is located"
                      >
                        <Input
                          name="mallName"
                          placeholder="Jamuna Future Park"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Number of Tables"
                        icon={Hash}
                        hint="You can update this later"
                      >
                        <Input
                          name="tablesCount"
                          type="number"
                          min="1"
                          max="999"
                          placeholder="40"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Restaurant Phone"
                        icon={Phone}
                        hint="For customer bookings & inquiries"
                        full
                      >
                        <Input
                          name="restaurantPhone"
                          placeholder="+880 1XXX-XXXXXX"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Restaurant Email"
                        icon={Mail}
                        hint="Public contact email for reservations"
                      >
                        <Input
                          name="restaurantEmail"
                          type="email"
                          placeholder="info@yourrestaurant.com"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Full Address"
                        icon={MapPin}
                        hint="Complete address for delivery and listings"
                        full
                      >
                        <Textarea
                          name="address"
                          placeholder="Level 3, Food Court Zone B, Jamuna Future Park, Dhaka"
                          required
                          className="rp-textarea"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>
                    </div>
                  </div>

                  {/* ── DIVIDER ── */}
                  <div className="rp-divider">
                    <div className="rp-divider-line" />
                    <span className="rp-divider-text">Admin Account</span>
                    <div className="rp-divider-line" />
                  </div>

                  {/* ── SECTION 2: Admin Account ── */}
                  <div className="rp-section">
                    <div className="rp-section-header">
                      <div
                        className="rp-section-icon"
                        style={{ background: "#f0fdf4" }}
                      >
                        <User size={15} color="#34a853" />
                      </div>
                      <div className="rp-section-text">
                        <span className="rp-section-title">
                          Your Admin Account
                        </span>
                        <span className="rp-section-num">Section 02 of 02</span>
                      </div>
                    </div>

                    <div className="rp-grid">
                      <Field
                        label="Your Name"
                        icon={User}
                        hint="For account verification"
                      >
                        <Input
                          name="ownerName"
                          placeholder="John Doe"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Login Email"
                        icon={Mail}
                        hint="You'll use this to sign in"
                      >
                        <Input
                          name="email"
                          type="email"
                          placeholder="admin@yourrestaurant.com"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36 }}
                        />
                      </Field>

                      <Field
                        label="Password"
                        icon={Lock}
                        hint="Minimum 6 characters"
                      >
                        <Input
                          name="password"
                          type={showPass ? "text" : "password"}
                          minLength={6}
                          placeholder="Create a strong password"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36, paddingRight: 40 }}
                        />
                        <button
                          type="button"
                          onClick={() => setShowPass((v) => !v)}
                          style={{
                            position: "absolute",
                            right: 12,
                            background: "none",
                            border: "none",
                            cursor: "pointer",
                            color: "#bbb",
                            padding: 0,
                            display: "flex",
                          }}
                        >
                          {showPass ? <EyeOff size={14} /> : <Eye size={14} />}
                        </button>
                      </Field>

                      <Field
                        label="Confirm Password"
                        icon={Lock}
                        hint="Must match your password"
                      >
                        <Input
                          name="confirmPassword"
                          type={showConfirm ? "text" : "password"}
                          minLength={6}
                          placeholder="Re-enter your password"
                          required
                          className="rp-input"
                          style={{ paddingLeft: 36, paddingRight: 40 }}
                        />
                        <button
                          type="button"
                          onClick={() => setShowConfirm((v) => !v)}
                          style={{
                            position: "absolute",
                            right: 12,
                            background: "none",
                            border: "none",
                            cursor: "pointer",
                            color: "#bbb",
                            padding: 0,
                            display: "flex",
                          }}
                        >
                          {showConfirm ? (
                            <EyeOff size={14} />
                          ) : (
                            <Eye size={14} />
                          )}
                        </button>
                      </Field>
                    </div>
                  </div>

                  {/* ── SUBMIT ── */}
                  <button
                    type="submit"
                    className="rp-submit"
                    disabled={loading}
                  >
                    {loading ? (
                      <>
                        <Loader2
                          size={16}
                          style={{ animation: "spin 1s linear infinite" }}
                        />
                        Creating your account…
                      </>
                    ) : (
                      <>
                        Create Restaurant Account
                        <ArrowRight size={16} />
                      </>
                    )}
                  </button>

                  <p className="rp-login-hint">
                    Already have an account?{" "}
                    <Link href="/login">Sign in here</Link>
                  </p>

                  {/* Trust signals */}
                  <div className="rp-trust">
                    <div className="rp-trust-item">
                      <Shield size={13} className="rp-trust-icon" />
                      No credit card
                    </div>
                    <div className="rp-trust-item">
                      <Gift size={13} className="rp-trust-icon" />
                      14-day free trial
                    </div>
                    <div className="rp-trust-item">
                      <Clock size={13} className="rp-trust-icon" />
                      Cancel anytime
                    </div>
                  </div>
                </form>
              </div>
            </div>
          </div>

          {/* Right sidebar — how it works */}
          <div className="rp-col-right">
            <p
              style={{
                fontSize: 11,
                fontWeight: 700,
                letterSpacing: 2,
                textTransform: "uppercase",
                color: "#bbb",
                marginBottom: 4,
              }}
            >
              How it works
            </p>
            {[
              {
                n: "01",
                title: "Register your restaurant",
                desc: "Fill in your restaurant details and create your admin account.",
              },
              {
                n: "02",
                title: "Set up your menu & tables",
                desc: "Add your menu items, configure tables, and customize your QR codes.",
              },
              {
                n: "03",
                title: "Start accepting orders",
                desc: "Go live instantly. Customers scan, order, and pay from their phones.",
              },
              {
                n: "04",
                title: "Track & grow",
                desc: "Use live analytics to optimize pricing, staffing, and peak hours.",
              },
            ].map((s, i) => (
              <div
                key={i}
                className="rp-step-item"
                style={{ animationDelay: `${0.3 + i * 0.1}s` }}
              >
                <div className="rp-step-num">{s.n}</div>
                <div>
                  <div className="rp-step-title">{s.title}</div>
                  <div className="rp-step-desc">{s.desc}</div>
                </div>
              </div>
            ))}

            {/* Security badge */}
            <div
              className="rp-step-item"
              style={{
                animationDelay: "0.75s",
                background: "#fafaf9",
                borderColor: "#f0f0ee",
              }}
            >
              <div
                className="rp-step-num"
                style={{ background: "#f0fdf4", color: "#34a853" }}
              >
                <Shield size={13} />
              </div>
              <div>
                <div className="rp-step-title">Bank-level security</div>
                <div className="rp-step-desc">
                  SOC 2 compliant · 256-bit encryption · Daily backups
                </div>
              </div>
            </div>
          </div>
        </main>

        {/* Footer */}
        <footer className="rp-footer">
          <span>© 2026 Restaurant SaaS · All rights reserved</span>
          <span>Privacy Policy · Terms of Service</span>
        </footer>

        {/* Floating social-proof badge */}
        <div className="rp-float-badge">
          <div className="rp-float-avatar">
            {["🧑‍🍳", "👨‍🍳", "👩‍🍳"].map((e, i) => (
              <span
                key={i}
                style={{ background: `hsl(${i * 40 + 20},60%,88%)` }}
              >
                {e}
              </span>
            ))}
          </div>
          <div className="rp-float-text">
            <strong>47 restaurants</strong>
            <span>joined this week</span>
          </div>
        </div>

        <style>{`
          @keyframes spin {
            from { transform: rotate(0deg); }
            to   { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    </>
  );
}

// components/DashboardHeader.jsx
"use client";

import { useCallback, useState } from "react";
import { Copy, QrCode, Bell, ShoppingBag, Zap } from "lucide-react";
import { toast } from "sonner";
import { usePathname, useRouter } from "next/navigation";
import { useNotifications } from "@/hooks/useNotifications";
import NotificationPanel from "@/components/NotificationPanel";

export default function DashboardHeader({ restaurant, user }) {
  const [showQR, setShowQR] = useState(false);
  const [showNotif, setShowNotif] = useState(false);
  const pathname = usePathname();
  const router = useRouter();

  // ── Notifications (no model changes — reads existing APIs + localStorage) ──
  const {
    notifications,
    unreadCount,
    orderCount,
    hotActionCount,
    markAllRead,
    markRead,
    refresh,
  } = useNotifications(restaurant?._id ?? null);

  // ── Page titles ────────────────────────────────────────────────────────────
  const titles = {
    "/dashboard": {
      title: "Dashboard",
      subtitle: `Hi ${user?.name || "User"}, Welcome to Menu Tiger Dashboard!`,
    },
    "/dashboard/menu": { title: "Menu", subtitle: "Craft your digital menu" },
    "/dashboard/orders": {
      title: "Orders",
      subtitle: "Manage customer orders",
    },
    "/dashboard/settings": {
      title: "Settings",
      subtitle: "Manage your restaurant preferences",
    },
  };
  const page = titles[pathname] || {
    title: "Dashboard",
    subtitle: "Welcome to Menu Tiger",
  };

  // ── Handlers ───────────────────────────────────────────────────────────────
  const handleCopy = async () => {
    await navigator.clipboard.writeText(restaurant.publicUrl);
    toast.success("Link copied!");
  };

  const handleBellClick = () => {
    const opening = !showNotif;
    setShowNotif(opening);
    if (opening) refresh(); // fresh pull on open
  };

  // Dismiss = mark that single notification read (localStorage only)
  const handleDismiss = useCallback((id) => markRead(id), [markRead]);

  const handleViewOrders = () => {
    setShowNotif(false);
    router.push(`/dashboard/${restaurant._id}/orders`);
  };

  if (!restaurant) return null;

  return (
    <>
      {/* ── Header bar ─────────────────────────────────────────────────────── */}
      <div className="bg-white dark:bg-[#0a1020] rounded-xl p-5 shadow-sm flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        {/* Left — page title */}
        <div>
          <h1 className="text-2xl font-bold dark:text-white">{page.title}</h1>
          <p className="text-gray-600 dark:text-gray-400">{page.subtitle}</p>
        </div>

        {/* Right — action buttons */}
        <div className="flex items-center gap-2">
          {/* ── 🔔 Bell ───────────────────────────────────────────────────── */}
          <div className="relative">
            <button
              onClick={handleBellClick}
              className="relative border rounded-lg px-3 py-2 bg-white dark:bg-[#0a1020] dark:border-white/10
                         hover:bg-gray-100 dark:hover:bg-white/10 transition flex items-center gap-2"
              aria-label="Notifications"
            >
              <Bell className="w-5 h-5 dark:text-gray-300" />

              {/* Red unread badge */}
              {unreadCount > 0 && (
                <span
                  key={unreadCount}
                  className="absolute -top-1.5 -right-1.5 min-w-[18px] h-[18px]
                             bg-red-500 text-white text-[10px] font-black
                             rounded-full flex items-center justify-center px-1 shadow-md"
                  style={{ animation: "popIn 0.25s ease-out" }}
                >
                  {unreadCount > 99 ? "99+" : unreadCount}
                </span>
              )}
            </button>

            {/* Dropdown panel */}
            {showNotif && (
              <NotificationPanel
                notifications={notifications}
                unreadCount={unreadCount}
                orderCount={orderCount}
                hotActionCount={hotActionCount}
                onMarkAllRead={markAllRead}
                onDismiss={handleDismiss}
                onClose={() => setShowNotif(false)}
                onViewOrders={handleViewOrders}
              />
            )}
          </div>

          {/* ── 🛒 Order mini-badge (only when there are unread orders) ──── */}
          {orderCount > 0 && (
            <button
              onClick={handleViewOrders}
              className="flex items-center gap-1.5 border border-emerald-200 dark:border-emerald-800
                         rounded-lg px-3 py-2 bg-emerald-50 dark:bg-emerald-950/40
                         text-emerald-700 dark:text-emerald-400
                         hover:bg-emerald-100 dark:hover:bg-emerald-900/50 transition text-xs font-bold"
              title="New orders waiting"
            >
              <ShoppingBag size={15} />
              {orderCount} new order{orderCount !== 1 ? "s" : ""}
            </button>
          )}

          {/* ── ⚡ Hot-action mini-badge (pulsing — most urgent) ──────────── */}
          {hotActionCount > 0 && (
            <button
              onClick={handleBellClick}
              className="flex items-center gap-1.5 border border-orange-200 dark:border-orange-800
                         rounded-lg px-3 py-2 bg-orange-50 dark:bg-orange-950/40
                         text-orange-700 dark:text-orange-400
                         hover:bg-orange-100 dark:hover:bg-orange-900/50 transition text-xs font-bold
                         animate-pulse"
              title="Table alerts need attention"
            >
              <Zap size={15} />
              {hotActionCount} alert{hotActionCount !== 1 ? "s" : ""}
            </button>
          )}

          {/* ── QR button ── */}
          <button
            onClick={() => setShowQR(true)}
            className="border rounded-lg px-4 py-2 bg-white dark:bg-[#0a1020] dark:border-white/10
                       flex items-center gap-2 hover:bg-gray-100 dark:hover:bg-white/10 transition
                       dark:text-gray-300"
          >
            <QrCode className="w-5 h-5" />
            <span className="hidden md:inline">QR Code</span>
          </button>

          {/* ── Copy link ── */}
          <button
            onClick={handleCopy}
            className="border rounded-lg px-4 py-2 bg-white dark:bg-[#0a1020] dark:border-white/10
                       flex items-center gap-2 hover:bg-gray-100 dark:hover:bg-white/10 transition
                       dark:text-gray-300"
          >
            <Copy className="w-5 h-5" />
            <span className="hidden md:inline">Copy Link</span>
          </button>

          {/* ── Open app ── */}
          <a
            href={restaurant.publicUrl}
            target="_blank"
            className="bg-emerald-500 text-white px-4 py-2 rounded-lg shadow
                       flex items-center gap-2 hover:bg-emerald-600 transition"
          >
            👁 <span className="hidden sm:inline">Open App</span>
          </a>
        </div>
      </div>

      {/* ── QR Modal ───────────────────────────────────────────────────────── */}
      {showQR && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <div className="bg-white dark:bg-[#0f1a2e] rounded-2xl p-6 w-full max-w-sm shadow-xl space-y-5 relative">
            <button
              onClick={() => setShowQR(false)}
              className="absolute top-3 right-3 text-gray-500 hover:text-gray-700 dark:text-gray-400 transition"
            >
              ✕
            </button>
            <h2 className="text-xl font-semibold text-center dark:text-white">
              Restaurant QR Code
            </h2>
            {/* NOTE: Remove stray * that was in original file */}
            <img
              src={restaurant.qrCodeBase64}
              alt="QR Code"
              className="w-48 h-48 mx-auto border rounded-xl"
            />
            <div className="text-center text-sm text-gray-600 dark:text-gray-400 break-all">
              {restaurant.publicUrl}
            </div>
            <div className="flex gap-3">
              <a
                href={restaurant.qrCodeBase64}
                download={`${restaurant.slug}-qr.png`}
                className="flex-1 border dark:border-white/10 rounded-lg py-2 text-center flex items-center
                           justify-center gap-2 hover:bg-gray-50 dark:hover:bg-white/5 dark:text-gray-300 transition"
              >
                ⬇ Download
              </a>
              <button
                onClick={handleCopy}
                className="flex-1 border dark:border-white/10 rounded-lg py-2 flex items-center
                           justify-center gap-2 hover:bg-gray-50 dark:hover:bg-white/5 dark:text-gray-300 transition"
              >
                📋 Copy Link
              </button>
            </div>
            <a
              href={restaurant.publicUrl}
              target="_blank"
              className="block text-center bg-emerald-500 text-white py-2 rounded-lg mt-2 hover:bg-emerald-600 transition"
            >
              👁 Open Menu
            </a>
          </div>
        </div>
      )}

      <style>{`
        @keyframes popIn {
          0%   { transform: scale(0.3); opacity: 0; }
          70%  { transform: scale(1.3); }
          100% { transform: scale(1);   opacity: 1; }
        }
        @keyframes dropIn {
          from { opacity: 0; transform: translateY(-6px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </>
  );
}

"use client";

import { useState } from "react";
import { X, UploadCloud } from "lucide-react";

export default function FoodFormModal({
  restaurantId,
  categoryId,
  initialData,
  onClose,
  onSaved,
}) {
  console.log("FoodFormModal opened with categoryId:", categoryId);

  const [form, setForm] = useState({
    name: initialData?.name || "",
    description: initialData?.description || "",
    price: initialData?.price || "",
    image: initialData?.image || "",
    isAvailable: initialData?.isAvailable ?? true,
  });

  const [uploading, setUploading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const isEdit = !!initialData;

  function handleChange(e) {
    const { name, value, type, checked } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  }

  async function handleImageUpload(file) {
    if (!file) return;

    const fd = new FormData();
    fd.append("file", file);

    setUploading(true);
    try {
      const res = await fetch("/api/upload", {
        method: "POST",
        body: fd,
      });

      if (!res.ok) {
        throw new Error("Failed to upload image");
      }

      const data = await res.json();
      setForm((prev) => ({ ...prev, image: data.url }));
    } catch (error) {
      console.error("Upload error:", error);
      alert("Failed to upload image. Please try again.");
    } finally {
      setUploading(false);
    }
  }

  async function handleSubmit(e) {
    e.preventDefault();

    if (!form.name.trim()) {
      alert("Food name is required");
      return;
    }

    if (!form.price || parseFloat(form.price) < 0) {
      alert("Valid price is required");
      return;
    }

    setSubmitting(true);

    try {
      const url = isEdit
        ? `/api/restaurants/${restaurantId}/foods/${initialData._id}`
        : `/api/restaurants/${restaurantId}/categories/${categoryId}/foods`;

      console.log("Submitting to URL:", url);
      console.log("CategoryId in submit:", categoryId);
      console.log("Form data:", form);

      const method = isEdit ? "PATCH" : "POST";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });

      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(
          errorData.message ||
            `Failed to ${isEdit ? "update" : "create"} food item`,
        );
      }

      const data = await res.json();
      console.log("API Response:", data);

      // Handle both response formats:
      // 1. API returns complete object: { _id, name, price, categoryId, ... }
      // 2. API returns just insertedId: { insertedId: "..." }
      let savedFood;
      if (isEdit) {
        savedFood = {
          ...form,
          _id: initialData._id,
          categoryId: initialData.categoryId,
        };
      } else {
        if (data._id) {
          // API returned complete object
          savedFood = { ...data, categoryId };
        } else if (data.insertedId) {
          // API returned just insertedId
          savedFood = { ...form, _id: data.insertedId, categoryId };
        } else {
          throw new Error("No ID in response from create food API");
        }
      }

      console.log("Food saved successfully:", savedFood);
      onSaved(savedFood, isEdit ? "update" : "create");
      setSubmitting(false);
    } catch (error) {
      console.error("Submit error:", error);
      alert(`Error: ${error.message}`);
      setSubmitting(false);
    }
  }

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
      <form
        onSubmit={handleSubmit}
        className="bg-white rounded-xl w-full max-w-lg p-6 space-y-4"
      >
        <div className="flex justify-between items-center">
          <h2 className="font-semibold">{isEdit ? "Edit Food" : "Add Food"}</h2>
          <button
            type="button"
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700"
          >
            <X />
          </button>
        </div>

        {/* Image Upload */}
        <div className="space-y-2">
          <label className="text-sm font-medium">Food Image</label>

          <div className="flex items-center gap-4">
            <div className="w-24 h-24 rounded-lg border bg-gray-50 flex items-center justify-center overflow-hidden">
              {form.image ? (
                <img
                  src={form.image}
                  alt="preview"
                  className="w-full h-full object-cover"
                />
              ) : (
                <UploadCloud className="text-gray-400" />
              )}
            </div>

            <label className="cursor-pointer text-sm bg-black text-white px-4 py-2 rounded-lg hover:bg-gray-800 transition disabled:opacity-50">
              {uploading ? "Uploading..." : "Upload Image"}
              <input
                type="file"
                accept="image/*"
                hidden
                disabled={uploading || submitting}
                onChange={(e) => {
                  if (e.target.files && e.target.files[0]) {
                    handleImageUpload(e.target.files[0]);
                  }
                }}
              />
            </label>
          </div>
        </div>

        <input
          name="name"
          placeholder="Food name"
          value={form.name}
          onChange={handleChange}
          className="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          required
          disabled={submitting}
        />

        <textarea
          name="description"
          placeholder="Description"
          value={form.description}
          onChange={handleChange}
          className="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          rows={3}
          disabled={submitting}
        />

        <input
          type="number"
          name="price"
          placeholder="Price"
          value={form.price}
          onChange={handleChange}
          step="0.01"
          min="0"
          className="w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          required
          disabled={submitting}
        />

        <label className="flex items-center gap-2 text-sm cursor-pointer">
          <input
            type="checkbox"
            name="isAvailable"
            checked={form.isAvailable}
            onChange={handleChange}
            disabled={submitting}
          />
          Available
        </label>

        <div className="flex justify-end gap-3 pt-2">
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 border rounded hover:bg-gray-50 transition"
            disabled={submitting}
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={uploading || submitting}
            className="px-4 py-2 bg-black text-white rounded hover:bg-gray-800 disabled:opacity-50 disabled:cursor-not-allowed transition"
          >
            {submitting ? "Saving..." : isEdit ? "Update" : "Create"}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSession } from "next-auth/react";
import { X } from "lucide-react";
import { usePlatformSettings } from "@/hooks/usePlatformSettings";
import { useState } from "react";

export default function MobileSidebar({ open, setOpen }) {
  const pathname = usePathname();
  const { data: session } = useSession();
  const { settings } = usePlatformSettings();
  const [expandedItems, setExpandedItems] = useState({});

  // ✅ Always available from session — no URL parsing needed
  const restaurantId = session?.user?.restaurantId;
  const userRole = session?.user?.role || "user";
  const restaurantName = session?.user?.restaurantName || "Restaurant";
  const isOwner = userRole === "owner";
  const isAdmin = userRole === "admin";

  const toggleSubmenu = (name) => {
    setExpandedItems((prev) => ({
      ...prev,
      [name]: !prev[name],
    }));
  };

  const menus = [
    // Owner-only section
    ...(isOwner
      ? [
          {
            section: "👑 OWNER PANEL",
            items: [
              {
                name: "Admin Dashboard",
                href: `/dashboard/admin`,
                icon: "📊",
                badge: "Admin",
              },
              { name: "Users", href: `/dashboard/admin/users`, icon: "👥" },
              {
                name: "Restaurants",
                href: `/dashboard/admin/restaurants`,
                icon: "🏢",
              },
              {
                name: "Restaurant Plans",
                href: `/dashboard/admin/restaurants-plans`,
                icon: "💳",
              },
              {
                name: "Platform Analytics",
                href: `/dashboard/admin/analytics`,
                icon: "📈",
              },
              {
                name: "Activity Logs",
                href: `/dashboard/admin/activity`,
                icon: "📋",
              },
              {
                name: "System Settings",
                href: `/dashboard/admin/settings`,
                icon: "⚙️",
              },
            ],
          },
        ]
      : []),
    // Admin section - for admin role
    ...(isAdmin && !isOwner
      ? [
          {
            section: "Admin",
            items: [
              { name: "Admin Dashboard", href: `/dashboard/admin`, icon: "👑" },
              { name: "Users", href: `/dashboard/admin/users`, icon: "👥" },
              {
                name: "Restaurants",
                href: `/dashboard/admin/restaurants`,
                icon: "🏢",
              },
              {
                name: "Restaurant Plans",
                href: `/dashboard/admin/restaurants-plans`,
                icon: "💳",
              },
              {
                name: "Analytics",
                href: `/dashboard/admin/analytics`,
                icon: "📊",
              },
              {
                name: "Activity Log",
                href: `/dashboard/admin/activity`,
                icon: "📋",
              },
            ],
          },
        ]
      : []),
    // Restaurant management section - only show if user has restaurantId
    ...(restaurantId && !isOwner
      ? [
          {
            section: "Main",
            items: [
              { name: "Dashboard", href: `/dashboard`, icon: "📊" },
              {
                name: "Orders",
                href: `/dashboard/${restaurantId}/orders`,
                icon: "🛒",
              },
            ],
          },
          {
            section: "Management",
            items: [
              { name: "Menus", href: `/dashboard/menu`, icon: "📋" },
              {
                name: "Table Management",
                href: `/dashboard/${restaurantId}/tables`,
                icon: "🪑",
              },
              {
                name: "Kitchen Display",
                href: `/dashboard/${restaurantId}/kitchen`,
                icon: "🍳",
                badge: "Beta",
              },
            ],
          },
          {
            section: "Business",
            items: [
              {
                name: "Stores",
                icon: "🏪",
                children: [
                  {
                    name: "All Stores",
                    href: `/dashboard/${restaurantId}/stores`,
                  },
                  {
                    name: "Add Store",
                    href: `/dashboard/${restaurantId}/stores/new`,
                  },
                ],
              },
              {
                name: "Marketing",
                icon: "📣",
                children: [
                  {
                    name: "Campaigns",
                    href: `/dashboard/${restaurantId}/marketing/campaigns`,
                  },
                  {
                    name: "Coupons",
                    href: `/dashboard/${restaurantId}/marketing/coupons`,
