                  style={{
                    background:
                      "linear-gradient(135deg, var(--green-dark), var(--green))",
                    color: "#000",
                    padding: "14px 26px",
                    borderRadius: 12,
                    fontSize: 15,
                    fontWeight: 700,
                    border: "none",
                    cursor: "pointer",
