                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    padding: "12px 16px",
                    borderBottom: "1px solid var(--border)",
                  }}
                >
                  <div style={{ display: "flex", gap: 6 }}>
                    {["#ff5f57", "#ffbd2e", "#28c840"].map((c) => (
                      <div
                        key={c}
                        style={{
                          width: 10,
                          height: 10,
                          borderRadius: "50%",
                          background: c,
                        }}
                      />
                    ))}
                  </div>
                  <div
                    style={{
                      fontSize: 11,
                      color: "var(--text-dim)",
                      fontFamily: "monospace",
                    }}
                  >
                    restaurant_scene.3d
                  </div>
                  <div
                    style={{
                      fontSize: 11,
                      color: "var(--green)",
                      display: "flex",
                      alignItems: "center",
                      gap: 4,
                    }}
                  >
                    <span
                      style={{
                        width: 6,
                        height: 6,
                        background: "var(--green)",
                        borderRadius: "50%",
                        animation: "glowPulse 1s infinite",
                      }}
                    />{" "}
                    LIVE
                  </div>
                </div>
                <div style={{ height: 380 }}>
                  <RestaurantScene />
                </div>
              </div>

              {/* Floating chips */}
              <div
                style={{
                  position: "absolute",
                  top: -16,
                  right: -20,
                  background: "var(--surface2)",
                  border: "1px solid var(--border)",
                  borderRadius: 12,
                  padding: "10px 14px",
                  animation: "floatY 3s 0s ease-in-out infinite",
                  boxShadow: "0 10px 30px rgba(0,0,0,0.5)",
                }}
              >
                <div
                  style={{
                    fontSize: 10,
                    color: "var(--text-dim)",
                    marginBottom: 2,
                  }}
                >
                  Today&apos;s Revenue
                </div>
                <div
                  className="syne"
                  style={{
                    fontSize: 20,
                    fontWeight: 700,
                    color: "var(--green)",
                  }}
                >
                  $12,847
                </div>
                <div style={{ fontSize: 10, color: "#4ade80" }}>
                  ↑ 23.4% vs yesterday
                </div>
              </div>
              <div
                style={{
                  position: "absolute",
                  bottom: 30,
                  left: -24,
                  background: "var(--surface2)",
                  border: "1px solid var(--border)",
                  borderRadius: 12,
                  padding: "10px 14px",
                  animation: "floatY 3.5s 0.5s ease-in-out infinite",
                  boxShadow: "0 10px 30px rgba(0,0,0,0.5)",
                }}
              >
                <div
                  style={{
                    fontSize: 10,
                    color: "var(--text-dim)",
                    marginBottom: 2,
                  }}
                >
                  Tables Active
                </div>
                <div
                  className="syne"
                  style={{ fontSize: 20, fontWeight: 700, color: "#0080ff" }}
