      >
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div className="stats-grid">
            {stats.map((s, i) => (
              <div
                key={i}
                className="card-reveal"
                style={{ transitionDelay: `${i * 0.1}s`, textAlign: "center" }}
              >
                <div
                  className="syne"
                  style={{
                    fontSize: "clamp(32px,4vw,52px)",
                    fontWeight: 800,
                    color: "var(--green)",
                    lineHeight: 1,
