          <div style={{ textAlign: "center", marginBottom: 64 }}>
            <div
              style={{
                display: "inline-block",
                fontSize: 11,
                fontWeight: 700,
                letterSpacing: 3,
                color: "var(--green)",
                textTransform: "uppercase",
                marginBottom: 16,
                background: "rgba(0,232,122,0.08)",
                padding: "5px 14px",
                borderRadius: 100,
              }}
