                    padding: "16px 20px",
                    borderRadius: 12,
                    cursor: "pointer",
                    border: `1px solid ${activeFeature === i ? f.color + "40" : "var(--border)"}`,
                    background:
                      activeFeature === i ? `${f.color}08` : "transparent",
                    transition: "all 0.3s cubic-bezier(0.34,1.2,0.64,1)",
                    transform:
                      activeFeature === i ? "translateX(6px)" : "translateX(0)",
                    display: "flex",
                    alignItems: "center",
                    gap: 14,
                  }}
                >
                  <div
                    style={{
                      width: 38,
                      height: 38,
                      borderRadius: 9,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      background:
                        activeFeature === i
                          ? `${f.color}20`
                          : "var(--surface3)",
                      color: activeFeature === i ? f.color : "var(--text-dim)",
                      transition: "all 0.3s ease",
                      flexShrink: 0,
                    }}
                  >
                    {f.icon}
                  </div>
                  <div>
                    <div
                      style={{
                        fontSize: 14,
                        fontWeight: 600,
                        color:
                          activeFeature === i
                            ? "var(--text)"
