                          color: f.color,
                          marginTop: 2,
                          fontWeight: 600,
                        }}
                      >
                        {f.stat}
                      </div>
                    )}
                  </div>
                  {activeFeature === i && (
                    <div
                      style={{
                        marginLeft: "auto",
                        width: 6,
                        height: 6,
                        borderRadius: "50%",
                        background: f.color,
                        boxShadow: `0 0 10px ${f.color}`,
                      }}
                    />
                  )}
                </div>
              ))}
