            {/* Feature detail */}
            <TiltCard
              style={{
                background: `linear-gradient(135deg, ${features[activeFeature].color}08, var(--surface2))`,
                border: `1px solid ${features[activeFeature].color}25`,
                borderRadius: 20,
                padding: 40,
                minHeight: 340,
                transition: "background 0.5s ease, border-color 0.5s ease",
              }}
