              <div
                style={{
                  width: 56,
                  height: 56,
                  borderRadius: 14,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  background: `${features[activeFeature].color}20`,
                  color: features[activeFeature].color,
                  marginBottom: 20,
                  fontSize: 28,
                  boxShadow: `0 0 30px ${features[activeFeature].color}30`,
