              <div
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 8,
                  background: `${features[activeFeature].color}15`,
                  border: `1px solid ${features[activeFeature].color}30`,
                  borderRadius: 8,
                  padding: "8px 14px",
                }}
              >
                <TrendingUp size={14} color={features[activeFeature].color} />
                <span
                  style={{
                    fontSize: 13,
                    fontWeight: 700,
                    color: features[activeFeature].color,
