                  borderRadius: 16,
                  padding: "36px 30px",
                  border: plan.highlight ? "none" : "1px solid var(--border)",
                  background: plan.highlight
                    ? "linear-gradient(135deg, #0a1a0f, #0f2018)"
                    : "var(--surface)",
                  transform: `${plan.highlight ? "scale(1.04)" : "scale(1)"} ${hoveredPlan === i ? "translateY(-8px)" : "translateY(0)"}`,
                  transition:
                    "transform 0.4s cubic-bezier(0.34,1.3,0.64,1), box-shadow 0.4s ease",
                  boxShadow:
                    hoveredPlan === i
                      ? `0 30px 60px rgba(0,0,0,0.5), 0 0 40px ${plan.highlight ? "rgba(0,232,122,0.2)" : "rgba(0,0,0,0.1)"}`
                      : plan.highlight
                        ? "0 20px 40px rgba(0,0,0,0.4)"
                        : "none",
                  transitionDelay: `${i * 0.1}s`,
                  cursor: "pointer",
                  position: "relative",
                  overflow: "hidden",
                }}
              >
                {plan.highlight && (
                  <div
                    style={{
                      position: "absolute",
                      top: 16,
                      right: 16,
                      background:
                        "linear-gradient(135deg, var(--green-dark), var(--green))",
                      color: "#000",
                      fontSize: 10,
                      fontWeight: 800,
                      padding: "4px 10px",
                      borderRadius: 100,
                      letterSpacing: 1,
                    }}
                  >
                    MOST POPULAR
                  </div>
                )}
                <div
                  style={{
                    marginBottom: 6,
                    fontSize: 11,
                    fontWeight: 700,
                    letterSpacing: 2,
                    color: plan.highlight ? "var(--green)" : "var(--text-dim)",
                    textTransform: "uppercase",
                  }}
                >
                  {plan.name}
                </div>
                <div
                  style={{
                    display: "flex",
                    alignItems: "baseline",
                    gap: 4,
                    marginBottom: 6,
                  }}
                >
                  <span
                    className="syne"
                    style={{ fontSize: 44, fontWeight: 800, letterSpacing: -2 }}
                  >
                    {plan.price}
                  </span>
                  <span style={{ fontSize: 14, color: "var(--text-dim)" }}>
                    {plan.period}
                  </span>
                </div>
                <p
                  style={{
                    fontSize: 13,
                    color: "var(--text-dim)",
                    marginBottom: 28,
                  }}
                >
                  {plan.description}
                </p>
                <MagBtn
                  style={{
                    width: "100%",
                    padding: "13px",
                    borderRadius: 10,
                    fontSize: 14,
                    fontWeight: 700,
                    background: plan.highlight
                      ? "linear-gradient(135deg, var(--green-dark), var(--green))"
                      : "var(--surface3)",
                    color: plan.highlight ? "#000" : "var(--text)",
                    border: plan.highlight ? "none" : "1px solid var(--border)",
                    cursor: "pointer",
                    marginBottom: 28,
                    boxShadow: plan.highlight
                      ? "0 0 20px rgba(0,232,122,0.3)"
                      : "none",
                  }}
                >
                  {plan.cta}
                </MagBtn>
                <div
                  style={{ display: "flex", flexDirection: "column", gap: 12 }}
                >
                  {plan.features.map((f, j) => (
                    <div
                      key={j}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 10,
                        fontSize: 13,
                        color: "var(--text-dim)",
                      }}
                    >
                      <Check
                        size={14}
                        color={plan.highlight ? "var(--green)" : "#4ade80"}
                        style={{ flexShrink: 0 }}
                      />{" "}
                      {f}
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── TESTIMONIALS ─────────────────────────────────── */}
      <section
        id="testimonials"
        style={{
          padding: "100px 24px",
          position: "relative",
          overflow: "hidden",
        }}
      >
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: 64 }}>
            <div
              style={{
                display: "inline-block",
                fontSize: 11,
                fontWeight: 700,
                letterSpacing: 3,
                color: "var(--gold)",
                textTransform: "uppercase",
                marginBottom: 16,
                background: "rgba(255,209,102,0.08)",
                padding: "5px 14px",
                borderRadius: 100,
              }}
            >
              Testimonials
            </div>
            <h2
              className="syne card-reveal"
              style={{
                fontSize: "clamp(28px,4vw,52px)",
                fontWeight: 800,
                letterSpacing: -1.5,
                marginBottom: 16,
              }}
            >
              Loved by restaurant teams
            </h2>
          </div>

          <div className="testi-grid">
            {testimonials.map((t, i) => (
              <TiltCard
                key={i}
                className="card-reveal hover-lift"
                style={{
                  background: "var(--surface2)",
                  border: "1px solid var(--border)",
                  borderRadius: 20,
                  padding: 32,
                  transitionDelay: `${i * 0.1}s`,
                }}
              >
                {/* Stars */}
                <div style={{ display: "flex", gap: 4, marginBottom: 20 }}>
                  {[...Array(t.stars)].map((_, j) => (
                    <Star key={j} size={14} fill="#ffd166" color="#ffd166" />
                  ))}
                </div>

                {/* Highlight pill */}
                <div
                  style={{
                    display: "inline-block",
                    background: "rgba(0,232,122,0.08)",
                    border: "1px solid rgba(0,232,122,0.15)",
                    color: "var(--green)",
                    fontSize: 11,
                    fontWeight: 700,
                    padding: "3px 10px",
                    borderRadius: 100,
                    marginBottom: 14,
                  }}
                >
                  {t.highlight}
                </div>

                <p
                  style={{
                    fontSize: 14,
                    color: "var(--text-dim)",
                    lineHeight: 1.75,
                    marginBottom: 24,
                    fontStyle: "italic",
                  }}
                >
                  &quot;{t.text}&quot;
                </p>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 12,
                    borderTop: "1px solid var(--border)",
                    paddingTop: 20,
                  }}
                >
                  <div style={{ fontSize: 28 }}>{t.flag}</div>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14 }}>
                      {t.name}
                    </div>
                    <div style={{ fontSize: 12, color: "var(--text-dim)" }}>
                      {t.role}
                    </div>
                  </div>
                </div>
              </TiltCard>
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA ──────────────────────────────────────────── */}
      <section
        style={{
          padding: "100px 24px",
          position: "relative",
          overflow: "hidden",
        }}
      >
        <FloatingOrb
          size={600}
          x="50%"
          y="50%"
          color="rgba(0,232,122,0.06)"
          blur={150}
        />
        <div
          style={{
            maxWidth: 680,
            margin: "0 auto",
            textAlign: "center",
            position: "relative",
            zIndex: 2,
          }}
        >
          <div
            style={{
              background: "var(--surface2)",
              border: "1px solid var(--border)",
              borderRadius: 24,
              padding: "60px 48px",
              boxShadow: "0 40px 80px rgba(0,0,0,0.4)",
            }}
          >
            <div
              className="animate-shimmer"
              style={{
                display: "inline-block",
                fontSize: 11,
                fontWeight: 700,
                letterSpacing: 3,
                color: "var(--green)",
                textTransform: "uppercase",
                marginBottom: 20,
                padding: "5px 16px",
                borderRadius: 100,
                border: "1px solid rgba(0,232,122,0.2)",
              }}
            >
              Get Started Today
            </div>
            <h2
              className="syne"
              style={{
                fontSize: "clamp(28px,4vw,48px)",
                fontWeight: 800,
                letterSpacing: -1.5,
                marginBottom: 16,
              }}
            >
              Ready to transform your restaurant?
            </h2>
            <p
              style={{
                color: "var(--text-dim)",
                fontSize: 16,
                marginBottom: 36,
                lineHeight: 1.7,
              }}
            >
              Join 12,000+ restaurants already growing with RestaurantOS. Start
              your free 14-day trial today.
            </p>

            {!submitted ? (
              <div
                style={{
                  display: "flex",
                  gap: 10,
                  maxWidth: 420,
                  margin: "0 auto 20px",
                }}
              >
                <input
                  type="email"
                  placeholder="Enter your email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSubmit(e)}
                  style={{
                    flex: 1,
                    padding: "13px 16px",
                    borderRadius: 10,
                    fontSize: 14,
                    background: "var(--surface)",
                    border: "1px solid var(--border)",
                    color: "var(--text)",
                    outline: "none",
                    transition: "border-color 0.2s",
                  }}
                  onFocus={(e) =>
                    (e.target.style.borderColor = "rgba(0,232,122,0.5)")
                  }
                  onBlur={(e) => (e.target.style.borderColor = "var(--border)")}
                />
                <MagBtn
                  onClick={handleSubmit}
                  style={{
                    padding: "13px 20px",
                    borderRadius: 10,
                    fontSize: 14,
                    fontWeight: 700,
                    background:
                      "linear-gradient(135deg, var(--green-dark), var(--green))",
                    color: "#000",
                    border: "none",
                    cursor: "pointer",
                    display: "flex",
                    alignItems: "center",
                    gap: 6,
                    whiteSpace: "nowrap",
                    boxShadow: "0 0 20px rgba(0,232,122,0.3)",
                  }}
                >
                  <Send size={14} /> Get Started
                </MagBtn>
              </div>
            ) : (
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  gap: 10,
                  padding: "16px 24px",
                  background: "rgba(0,232,122,0.08)",
                  border: "1px solid rgba(0,232,122,0.2)",
                  borderRadius: 12,
                  marginBottom: 20,
                  animation: "scaleIn 0.4s ease",
                }}
              >
                <Check size={18} color="var(--green)" />
                <span style={{ color: "var(--green)", fontWeight: 600 }}>
                  You&apos;re on the list! We&apos;ll be in touch shortly.
                </span>
              </div>
            )}

            <div
              style={{
                display: "flex",
                justifyContent: "center",
                gap: 24,
                flexWrap: "wrap",
              }}
            >
              {["No credit card", "Setup in minutes", "Cancel anytime"].map(
                (t) => (
                  <div
                    key={t}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 6,
                      fontSize: 12,
                      color: "var(--text-dim)",
                    }}
                  >
                    <Check size={11} color="var(--green)" /> {t}
                  </div>
                ),
              )}
            </div>
          </div>
        </div>
      </section>

      {/* ── FOOTER ───────────────────────────────────────── */}
      <footer
        style={{
          background: "var(--surface)",
          borderTop: "1px solid var(--border)",
          padding: "60px 24px 32px",
        }}
      >
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div className="footer-grid">
            <div>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                  marginBottom: 16,
                }}
              >
                <div
                  style={{
                    width: 34,
                    height: 34,
                    borderRadius: 8,
                    background:
                      "linear-gradient(135deg, var(--green-dark), var(--blue-mid))",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                  }}
                >
                  {platformSettings.platformLogo ? (
                    <img
                      src={platformSettings.platformLogo}
                      alt="Platform logo"
                      style={{
                        width: "100%",
                        height: "100%",
                        objectFit: "cover",
                        borderRadius: 6,
                      }}
                    />
                  ) : (
                    <ChefHat size={18} color="#fff" />
                  )}
                </div>
                <span
                  className="syne"
                  style={{ fontSize: 16, fontWeight: 700 }}
                >
                  {platformSettings.platformName}
                </span>
              </div>
              <p
                style={{
                  fontSize: 13,
                  color: "var(--text-dim)",
                  lineHeight: 1.7,
                  maxWidth: 240,
                }}
              >
                The all-in-one platform for modern restaurants to thrive in a
                competitive world.
              </p>
            </div>
            {[
              {
                label: "Product",
                links: ["Features", "Pricing", "Security", "Changelog"],
              },
              {
                label: "Company",
                links: ["About", "Blog", "Careers", "Press"],
              },
              {
                label: "Legal",
                links: ["Privacy", "Terms", "Cookies", "Contact"],
              },
            ].map((col) => (
              <div key={col.label}>
                <div
                  style={{
                    fontSize: 11,
                    fontWeight: 700,
                    letterSpacing: 2,
                    textTransform: "uppercase",
                    color: "var(--text-dim)",
                    marginBottom: 16,
                  }}
                >
                  {col.label}
                </div>
                {col.links.map((l) => (
                  <a
                    key={l}
                    href="#"
                    style={{
                      display: "block",
                      fontSize: 13,
                      color: "var(--text-dim)",
                      textDecoration: "none",
                      marginBottom: 10,
                      transition: "color 0.2s",
                    }}
                    onMouseEnter={(e) =>
                      (e.target.style.color = "var(--green)")
                    }
                    onMouseLeave={(e) =>
                      (e.target.style.color = "var(--text-dim)")
                    }
                  >
                    {l}
                  </a>
                ))}
              </div>
            ))}
          </div>
          <div
            style={{
              borderTop: "1px solid var(--border)",
              paddingTop: 24,
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <p style={{ fontSize: 12, color: "var(--text-dim)" }}>
              © 2026 {platformSettings.platformName}. All rights reserved.
            </p>
            <div style={{ display: "flex", gap: 20 }}>
              {["Twitter", "LinkedIn", "GitHub"].map((s) => (
                <a
                  key={s}
                  href="#"
                  style={{
                    fontSize: 12,
                    color: "var(--text-dim)",
                    textDecoration: "none",
                    transition: "color 0.2s",
                  }}
                  onMouseEnter={(e) => (e.target.style.color = "var(--green)")}
                  onMouseLeave={(e) =>
                    (e.target.style.color = "var(--text-dim)")
                  }
                >
                  {s}
                </a>
              ))}
            </div>
          </div>
        </div>
      </footer>

      {/* ── RESPONSIVE ───────────────────────────────────── */}
      <style>{`
        /* ── Hero 2-column grid ── */
        .hero-grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 48px;
          align-items: center;
          width: 100%;
        }

        /* ── Other section grids ── */
        .stats-grid   { display: grid; grid-template-columns: repeat(4,1fr); gap: 40px; }
        .feat-tabs    { display: grid; grid-template-columns: 1fr 1fr; gap: 40px; align-items: start; }
        .feat-grid    { display: grid; grid-template-columns: repeat(3,1fr); gap: 20px; }
        .pricing-grid { display: grid; grid-template-columns: repeat(3,1fr); gap: 24px; align-items: start; }
        .testi-grid   { display: grid; grid-template-columns: repeat(3,1fr); gap: 24px; }
        .footer-grid  { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 48px; margin-bottom: 48px; }

        /* ── 1024px ── */
        @media (max-width: 1024px) {
          .feat-grid    { grid-template-columns: repeat(2,1fr); }
          .footer-grid  { grid-template-columns: 1fr 1fr; gap: 32px; }
        }

        /* ── 768px: single column ── */
        @media (max-width: 768px) {
          .hero-grid    { grid-template-columns: 1fr; gap: 32px; }
          .stats-grid   { grid-template-columns: repeat(2,1fr); gap: 24px; }
          .feat-tabs    { grid-template-columns: 1fr; }
          .feat-grid    { grid-template-columns: 1fr; }
          .pricing-grid { grid-template-columns: 1fr; }
          .testi-grid   { grid-template-columns: 1fr; }
          .footer-grid  { grid-template-columns: 1fr 1fr; gap: 28px; }
          .hidden-mobile { display: none !important; }
          .mobile-only   { display: block !important; }
        }

        @media (max-width: 480px) {
          .stats-grid  { grid-template-columns: 1fr 1fr; }
          .footer-grid { grid-template-columns: 1fr; }
        }

        @media (min-width: 769px) {
          .mobile-only { display: none !important; }
        }
      `}</style>
    </div>
  );
}

"use client";
// FILE: components/TableRequestsPanel.jsx
// Drop into your restaurant dashboard layout.
// Polls /api/restaurants/[id]/table-requests every 8s.
// Plays a subtle sound + shows badge when new requests arrive.
//
// Usage:
//   <TableRequestsPanel restaurantId={restaurant._id} />

import { useState, useEffect, useRef, useCallback } from "react";

// ── Styles ────────────────────────────────────────────────────────────────────
const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600&family=DM+Mono:wght@300;400&display=swap');

  .trp-root {
    --bg:       #05050a;
    --surface:  #0c0c14;
    --card:     #111118;
    --border:   rgba(255,255,255,0.07);
    --gold:     #d4a853;
    --gold-dim: rgba(212,168,83,0.1);
    --cream:    #f0e6d0;
    --muted:    rgba(240,230,208,0.4);
    --green:    #27ae60;
    --blue:     #2980b9;
    --purple:   #8e44ad;
    --red:      #c0392b;

    font-family: 'Outfit', sans-serif;
    font-weight: 300;
    color: var(--cream);
    width: 100%;
  }

  /* ── HEADER BAR ── */
  .trp-header {
    display: flex; align-items: center; justify-content: space-between;
    padding: 20px 24px 16px;
    border-bottom: 1px solid var(--border);
    background: var(--surface);
    border-radius: 8px 8px 0 0;
  }
  .trp-header-left { display: flex; align-items: center; gap: 12px; }
  .trp-header-icon {
    width: 36px; height: 36px; border-radius: 6px; flex-shrink: 0;
    background: var(--gold-dim);
    border: 1px solid rgba(212,168,83,0.2);
    display: flex; align-items: center; justify-content: center;
    font-size: 16px;
  }
  .trp-header-title {
    font-size: 15px; font-weight: 600; color: var(--cream);
  }
  .trp-header-sub {
    font-size: 11px; color: var(--muted); margin-top: 1px;
    font-family: 'DM Mono', monospace; letter-spacing: 0.06em;
  }
  .trp-header-right { display: flex; align-items: center; gap: 10px; }

  /* Live indicator */
  .trp-live {
    display: flex; align-items: center; gap: 6px;
    font-size: 10px; letter-spacing: 0.1em; text-transform: uppercase;
    color: var(--green);
    font-family: 'DM Mono', monospace;
  }
  .trp-live-dot {
    width: 6px; height: 6px; border-radius: 50%; background: var(--green);
    animation: livePulse 2s infinite;
  }
  @keyframes livePulse {
    0%,100%{opacity:1;transform:scale(1)} 50%{opacity:.4;transform:scale(1.3)}
  }

  /* Pending badge */
  .trp-badge {
    min-width: 22px; height: 22px; border-radius: 100px;
    background: var(--red); color: #fff;
    font-size: 11px; font-weight: 700;
    display: flex; align-items: center; justify-content: center;
    padding: 0 5px;
    animation: badgeIn .3s ease;
  }
  @keyframes badgeIn { from{transform:scale(0)} to{transform:scale(1)} }

  /* Filter tabs */
  .trp-tabs {
    display: flex; gap: 0;
    background: var(--bg);
    border-bottom: 1px solid var(--border);
    overflow-x: auto;
  }
  .trp-tab {
    flex: 1; padding: 12px 16px;
    font-size: 12px; font-weight: 500; letter-spacing: 0.06em;
    cursor: pointer; border: none; background: transparent;
    color: var(--muted); border-bottom: 2px solid transparent;
    transition: all .2s; font-family: 'Outfit', sans-serif;
    white-space: nowrap;
  }
  .trp-tab:hover { color: var(--cream); }
  .trp-tab.active { color: var(--gold); border-bottom-color: var(--gold); }

  /* ── REQUEST LIST ── */
  .trp-list {
    background: var(--bg);
    border-radius: 0 0 8px 8px;
    border: 1px solid var(--border);
    border-top: none;
    min-height: 200px;
    max-height: 520px;
    overflow-y: auto;
  }
  .trp-list::-webkit-scrollbar { width: 4px; }
  .trp-list::-webkit-scrollbar-track { background: transparent; }
  .trp-list::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

  /* Empty state */
  .trp-empty {
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    padding: 60px 20px;
    color: var(--muted); text-align: center; gap: 10px;
  }
  .trp-empty-icon { font-size: 40px; opacity: .5; }
  .trp-empty-text { font-size: 14px; }

  /* Request card */
  .trp-item {
    display: flex; align-items: flex-start; gap: 14px;
    padding: 16px 20px;
    border-bottom: 1px solid var(--border);
    transition: background .2s;
    animation: itemIn .35s cubic-bezier(.22,1,.36,1);
    position: relative;
  }
  @keyframes itemIn {
    from { opacity:0; transform: translateX(12px); }
    to   { opacity:1; transform: translateX(0); }
  }
  .trp-item:last-child { border-bottom: none; }
  .trp-item:hover { background: rgba(255,255,255,0.02); }
  .trp-item.new { background: rgba(212,168,83,0.05); }

  /* Action icon bubble */
  .trp-item-icon {
    width: 42px; height: 42px; border-radius: 10px; flex-shrink: 0;
    display: flex; align-items: center; justify-content: center;
    font-size: 20px;
  }

  .trp-item-body { flex: 1; min-width: 0; }
  .trp-item-top {
    display: flex; align-items: center; gap: 8px; flex-wrap: wrap; margin-bottom: 4px;
  }
  .trp-item-action {
    font-size: 14px; font-weight: 600; color: var(--cream);
  }
  .trp-item-table {
    font-family: 'DM Mono', monospace;
    font-size: 11px; color: var(--gold);
    background: var(--gold-dim);
    border: 1px solid rgba(212,168,83,0.2);
    padding: 2px 8px; border-radius: 100px;
    letter-spacing: 0.06em;
  }
  .trp-item-time {
    font-size: 11px; color: var(--muted);
    font-family: 'DM Mono', monospace;
    margin-left: auto; flex-shrink: 0;
  }
  .trp-item-note {
    font-size: 12px; color: var(--muted); margin-top: 2px;
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
  }

  /* Status chip */
  .trp-status {
    font-size: 10px; font-weight: 600; letter-spacing: 0.1em; text-transform: uppercase;
    padding: 3px 9px; border-radius: 100px;
    font-family: 'DM Mono', monospace;
  }
  .trp-status.pending      { background: rgba(212,168,83,0.15); color: #d4a853; border: 1px solid rgba(212,168,83,0.25); }
  .trp-status.acknowledged { background: rgba(41,128,185,0.15); color: #2980b9; border: 1px solid rgba(41,128,185,0.25); }
